@st.cache_data(show_spinner=False)
def ats_template_options():
    try:
        return json.loads(zlib.decompress(base64.b64decode(ATS_TEMPLATE_OPTIONS_B64)).decode("utf-8"))
    except Exception:
        return ATS_FALLBACK_OPTIONS

def ats_options(nome):
    dados = ats_template_options()
    vals = dados.get(nome) or ATS_FALLBACK_OPTIONS.get(nome, [])
    return [str(v).strip() for v in vals if str(v or "").strip()]

