def get_versao_ativa_maquinas(db, tipo_checklist):
    return db.query(ChecklistVersaoMaquinas).filter_by(tipo_checklist=tipo_checklist, ativo=True).order_by(ChecklistVersaoMaquinas.versao.desc(), ChecklistVersaoMaquinas.id.desc()).first()

def criar_versao_checklist_maquinas(db, tipo_checklist, criado_por="Sistema", descricao=None, base_version=None):
    atual = db.query(ChecklistVersaoMaquinas).filter_by(tipo_checklist=tipo_checklist).order_by(ChecklistVersaoMaquinas.versao.desc()).first()
    nova_num = (atual.versao if atual and atual.versao else 0) + 1
    for v in db.query(ChecklistVersaoMaquinas).filter_by(tipo_checklist=tipo_checklist, ativo=True).all():
        v.ativo = False
    v = ChecklistVersaoMaquinas(tipo_checklist=tipo_checklist, versao=nova_num, descricao=descricao or f"Versão {nova_num} de {tipo_checklist}", ativo=True, criado_por=criado_por)
    db.add(v); db.flush()
    if base_version:
        perguntas = db.query(ChecklistPerguntaVersaoMaquinas).filter_by(checklist_versao_id=base_version.id).order_by(ChecklistPerguntaVersaoMaquinas.ordem).all()
        for p in perguntas:
            db.add(ChecklistPerguntaVersaoMaquinas(checklist_versao_id=v.id, item_base_id=p.item_base_id, ordem=p.ordem, pergunta=p.pergunta, item_critico=p.item_critico, gera_pac_automatico=p.gera_pac_automatico, ativo=p.ativo))
    else:
        itens = db.query(ChecklistItemNR12).filter_by(tipo_checklist=tipo_checklist).order_by(ChecklistItemNR12.ordem).all()
        for it in itens:
            db.add(ChecklistPerguntaVersaoMaquinas(checklist_versao_id=v.id, item_base_id=it.id, ordem=it.ordem, pergunta=it.pergunta, item_critico=it.item_critico, gera_pac_automatico=getattr(it, "gera_pac_automatico", False), ativo=it.ativo))
    db.flush()
    return v

def criar_versao_checklist_ehs(db, criado_por="Sistema", descricao=None):
    """Cria uma nova versão ativa do checklist EHS a partir da base editável atual.

    A base inicial continua no código como seed, mas a gestão operacional passa a ser pelo banco.
    Cada nova auditoria recebe um snapshot da versão ativa, preservando rastreabilidade histórica.
    """
    atual = db.query(ChecklistVersaoEHS).order_by(ChecklistVersaoEHS.versao.desc(), ChecklistVersaoEHS.id.desc()).first()
    nova_num = (atual.versao if atual and atual.versao else 0) + 1
    for v in db.query(ChecklistVersaoEHS).filter_by(ativo=True).all():
        v.ativo = False
    nova = ChecklistVersaoEHS(descricao=descricao or f"Versão {nova_num} do checklist de Diretrizes EHS", versao=nova_num, ativo=True, criado_por=criado_por)
    db.add(nova); db.flush()
    reqs = db.query(RequisitoEHS).join(DiretivaEHS).filter(RequisitoEHS.ativo==True, DiretivaEHS.ativo==True).order_by(DiretivaEHS.categoria, RequisitoEHS.ordem).all()
    for r in reqs:
        db.add(ChecklistPerguntaVersaoEHS(
            checklist_versao_id=nova.id,
            requisito_id=r.id,
            categoria=r.diretiva.categoria if r.diretiva else "Sem categoria",
            ordem=r.ordem,
            pergunta=r.pergunta,
            criticidade=r.criticidade,
            evidencia_esperada=r.evidencia_esperada,
            gera_pac_automatico=getattr(r, "gera_pac_automatico", False),
            ativo=r.ativo,
        ))
    db.flush()
    return nova


def ensure_ehs_checklist_412_version(db):
    """Garante que a versão ativa do checklist de auditoria reflita as Diretrizes EHS 4.12 e os procedimentos de alto risco integrados."""
    checklist_atual = checklist_ehs_unificado()
    globals()["CHECKLIST_EHS"] = checklist_atual
    categorias_esperadas = set(checklist_atual.keys())
    total_esperado = sum(len(v) for v in checklist_atual.values())
    ativa = db.query(ChecklistVersaoEHS).filter_by(ativo=True).order_by(ChecklistVersaoEHS.versao.desc(), ChecklistVersaoEHS.id.desc()).first()
    if not ativa:
        criar_versao_checklist_ehs(db, "Sistema", "Versão ativa baseada nas Diretrizes Globais de EHS 4.12 e nos Procedimentos de Alto Risco")
        return
    perguntas_ativas = db.query(ChecklistPerguntaVersaoEHS).filter_by(checklist_versao_id=ativa.id, ativo=True).all()
    cats_ativas = {p.categoria for p in perguntas_ativas}
    perguntas_por_cat = {}
    for p in perguntas_ativas:
        perguntas_por_cat.setdefault(p.categoria, set()).add(_ehs_norm_question(p.pergunta))
    cobertura_ok = (cats_ativas == categorias_esperadas) and (len(perguntas_ativas) == total_esperado)
    perguntas_ok = True
    for cat, pergs in checklist_atual.items():
        existentes = perguntas_por_cat.get(cat, set())
        if len(existentes) != len(pergs):
            perguntas_ok = False
            break
        for pergunta in pergs:
            if _ehs_norm_question(pergunta) not in existentes:
                perguntas_ok = False
                break
        if not perguntas_ok:
            break
    descricao_ativa = str(getattr(ativa, "descricao", "") or "")
    versao_atual = CHECKLIST_EHS_REVISAO in descricao_ativa
    if cobertura_ok and perguntas_ok and versao_atual and not any(str(c).startswith("Categoria ") for c in cats_ativas):
        return
    criar_versao_checklist_ehs(db, "Sistema", f"Checklist essencial revisado em português — {CHECKLIST_EHS_REVISAO}")

def seed_checklist_versions(db):
    tipos = {t for t, in db.query(ChecklistItemNR12.tipo_checklist).distinct().all()}
    for tipo in sorted(tipos):
        if not db.query(ChecklistVersaoMaquinas).filter_by(tipo_checklist=tipo).first():
            criar_versao_checklist_maquinas(db, tipo, "Sistema", "Versão inicial migrada do checklist padrão")
    if not db.query(ChecklistVersaoEHS).first():
        criar_versao_checklist_ehs(db, "Sistema", "Versão inicial migrada do checklist de Diretrizes EHS")

def sync_checklists_base(db):
    for tipo, itens in CHECKLIST_NR12.items():
        for i, (pergunta, critico) in enumerate(itens, 1):
            item = db.query(ChecklistItemNR12).filter_by(tipo_checklist=tipo, ordem=i).first()
            if not item:
                db.add(ChecklistItemNR12(tipo_checklist=tipo, ordem=i, pergunta=pergunta, item_critico=critico, gera_pac_automatico=False, ativo=True))
    checklist_ehs_atual = checklist_ehs_unificado()
    globals()["CHECKLIST_EHS"] = checklist_ehs_atual
    categorias_ativas_ehs = set(checklist_ehs_atual.keys())
    for d_old in db.query(DiretivaEHS).all():
        if d_old.categoria not in categorias_ativas_ehs:
            d_old.ativo = False
            for req_old in db.query(RequisitoEHS).filter_by(diretiva_id=d_old.id).all():
                req_old.ativo = False
    for cat, pergs in checklist_ehs_atual.items():
        d = db.query(DiretivaEHS).filter_by(categoria=cat).first()
        if not d:
            d = DiretivaEHS(categoria=cat, descricao=cat, ativo=True)
            db.add(d)
            db.flush()
        d.ativo = True
        d.descricao = cat
        ordens_esperadas = set(range(1, len(pergs)+1))
        for req_old in db.query(RequisitoEHS).filter_by(diretiva_id=d.id).all():
            if req_old.ordem not in ordens_esperadas:
                req_old.ativo = False
        for i, p in enumerate(pergs, 1):
            req = db.query(RequisitoEHS).filter_by(diretiva_id=d.id, ordem=i).first()
            criticidade = "Alta" if i == 1 else "Média"
            if not req:
                db.add(RequisitoEHS(diretiva_id=d.id, ordem=i, pergunta=p, criticidade=criticidade, evidencia_esperada="Evidência documental, registros, entrevistas e/ou verificação em campo.", gera_pac_automatico=False, ativo=True))
            else:
                req.pergunta = p
                req.criticidade = req.criticidade if req.criticidade in CRITICIDADES else criticidade
                req.evidencia_esperada = req.evidencia_esperada or "Evidência documental, registros, entrevistas e/ou verificação em campo."
                req.ativo = True
    db.flush()
    # Atualiza snapshots de auditorias existentes para remover versões antigas ou traduções automáticas ruins.
    for req in db.query(RequisitoEHS).filter(RequisitoEHS.ativo == True).all():
        db.query(RespostaAuditoriaEHS).filter(RespostaAuditoriaEHS.requisito_id == req.id).update({
            "pergunta_snapshot": req.pergunta,
            "criticidade_snapshot": req.criticidade,
            "evidencia_esperada_snapshot": req.evidencia_esperada,
        }, synchronize_session=False)
    db.flush()
    seed_checklist_versions(db)
    ensure_ehs_checklist_412_version(db)


def seed_regras_frequencia(db):
    for tipo, regras in REGRAS_FREQUENCIA_DEFAULT.items():
        for criticidade, dias in regras.items():
            obj = db.query(RegraFrequenciaInspecaoMaquinas).filter_by(tipo_evento=tipo, criticidade=criticidade).first()
            if not obj:
                db.add(RegraFrequenciaInspecaoMaquinas(
                    tipo_evento=tipo,
                    criticidade=criticidade,
                    dias_periodicidade=int(dias),
                    ativo=True,
                    atualizado_por="Sistema",
                    observacoes="Carga inicial padrão"
                ))
    db.flush()

def regra_frequencia_dias(db, tipo_evento, criticidade):
    criticidade = criticidade if criticidade in CRITICIDADES else "Média"
    obj = db.query(RegraFrequenciaInspecaoMaquinas).filter_by(tipo_evento=tipo_evento, criticidade=criticidade, ativo=True).first()
    if obj and obj.dias_periodicidade is not None:
        return int(obj.dias_periodicidade)
    return int(REGRAS_FREQUENCIA_DEFAULT.get(tipo_evento, {}).get(criticidade, 180))

def data_limite_por_frequencia(db, tipo_evento, criticidade, data_base=None):
    dias = regra_frequencia_dias(db, tipo_evento, criticidade)
    data_base = as_date(data_base) or date.today()
    return data_base + timedelta(days=max(0, dias))

def validar_data_dentro_limite(db, tipo_evento, criticidade, data_alvo, data_base=None):
    data_alvo = as_date(data_alvo)
    limite = data_limite_por_frequencia(db, tipo_evento, criticidade, data_base)
    if not data_alvo:
        return False, limite, f"Informe uma data até {fmt_date(limite)}."
    if data_alvo > limite:
        return False, limite, f"A data selecionada ultrapassa o limite permitido para criticidade {criticidade}: máximo {fmt_date(limite)}."
    return True, limite, ""

def df_regras_frequencia(db):
    rows = []
    regras = db.query(RegraFrequenciaInspecaoMaquinas).order_by(RegraFrequenciaInspecaoMaquinas.tipo_evento, RegraFrequenciaInspecaoMaquinas.criticidade).all()
    for r in regras:
        rows.append({
            "ID": r.id,
            "Tipo de evento": r.tipo_evento,
            "Criticidade": r.criticidade,
            "Dias máximos": r.dias_periodicidade,
            "Ativo": r.ativo,
            "Atualizado em": fmt_date(r.atualizado_em),
            "Atualizado por": r.atualizado_por,
            "Observações": r.observacoes,
        })
    return pd.DataFrame(rows)

def normalizar_perfil_acesso(perfil):
    mapa = {
        "Admin_LAG": PERFIL_MASTER,
        "EHS_Local": PERFIL_TECNICO_EHS,
        "Auditor": PERFIL_TECNICO_EHS,
        "Manutencao": PERFIL_TECNICO_EHS,
        "Producao_Operacao": PERFIL_TECNICO_EHS,
        "Engenharia": PERFIL_TECNICO_EHS,
        "Responsavel_Acao": PERFIL_TECNICO_EHS,
        "Visualizador": PERFIL_VISUALIZADOR,
        PERFIL_MASTER: PERFIL_MASTER,
        PERFIL_TECNICO_EHS: PERFIL_TECNICO_EHS,
        PERFIL_VISUALIZADOR: PERFIL_VISUALIZADOR,
        PERFIL_PERSONALIZADO: PERFIL_PERSONALIZADO,
        "Personalizado": PERFIL_PERSONALIZADO,
    }
    return mapa.get(str(perfil or "").strip(), PERFIL_VISUALIZADOR)

def senha_hash_segura(senha, salt=None):
    salt = salt or os.urandom(16).hex()
    senha = str(senha or "")
    return salt, hashlib.sha256((salt + senha).encode("utf-8")).hexdigest()

def set_user_password(usuario, senha):
    salt, h = senha_hash_segura(senha)
    usuario.senha_salt = salt
    usuario.senha_hash = h
    usuario.atualizado_em = datetime.utcnow()

def verify_user_password(usuario, senha):
    if not usuario or not getattr(usuario, "senha_hash", None) or not getattr(usuario, "senha_salt", None):
        return False
    _, h = senha_hash_segura(senha, usuario.senha_salt)
    return h == usuario.senha_hash

def is_master_user(u):
    """Perfil com visão gerencial LAG.

    Qualquer usuário marcado como master ou cadastrado como Gerencial LAG
    visualiza todos os sites e os consolidados LAG.
    """
    if not u or not getattr(u, "ativo", True):
        return False
    perfil = normalizar_perfil_acesso(getattr(u, "perfil", None))
    return bool(getattr(u, "is_master", False) or perfil == PERFIL_MASTER)

def is_super_admin_user(u):
    """Administrador principal do sistema para governança de acessos e atualização de bases."""
    return bool(is_master_user(u) and str(getattr(u, "nome", "")).strip().lower() == "eduardo")

def can_update_bases(u):
    return is_super_admin_user(u)

def init_db():
    Base.metadata.create_all(engine); ensure_schema_updates(); db=SessionLocal()
    try:
        if not db.query(Site).filter_by(codigo="Corporativo").first(): db.add(Site(codigo="Corporativo",nome="Corporativo"))
        for s in SITES_PADRAO:
            site_obj = db.query(Site).filter_by(codigo=s).first()
            nome_padrao = SITE_NOMES_PADRAO.get(s, s)
            if not site_obj:
                db.add(Site(codigo=s, nome=nome_padrao))
            else:
                site_obj.nome = nome_padrao
        db.flush()
        for item in USUARIOS_PADRAO:
            nome, perfil, sitecod, senha, master = item
            stt = db.query(Site).filter_by(codigo=sitecod).first()
            user = db.query(Usuario).filter_by(nome=nome).first()
            if not user:
                user = Usuario(nome=nome, perfil=perfil, site_id=stt.id if stt else None, ativo=True, is_master=bool(master))
                db.add(user)
                db.flush()
            user.perfil = perfil
            user.site_id = stt.id if stt else user.site_id
            user.ativo = True
            user.is_master = bool(master)
            set_user_password(user, senha)
        corp = db.query(Site).filter_by(codigo="Corporativo").first()
        for user in db.query(Usuario).all():
            user.perfil = normalizar_perfil_acesso(user.perfil)
            if not getattr(user, "senha_hash", None):
                set_user_password(user, SENHA_PADRAO_NOVO_USUARIO)
            if user.perfil == PERFIL_MASTER:
                user.is_master = True
                if corp:
                    user.site_id = corp.id
            else:
                user.is_master = False
        sync_checklists_base(db)
        seed_regras_frequencia(db)
        seed_energia_parametros(db)
        seed_energia_actual_hours_inicial(db)
        seed_energia_registros_inicial(db)
        seed_near_miss_inicial(db)
        seed_legal_inicial(db)
        seed_procedimentos_alto_risco_inicial(db)
        for maq in db.query(MaquinaNR12).all():
            maq.status_nr12 = normalizar_status_nr12(maq.status_nr12)
        db.commit()
        if db.query(MaquinaNR12).count()==0:
            sjc=db.query(Site).filter_by(codigo="SJC").first()
            m=MaquinaNR12(codigo="SJC-PRENSA-001",site_id=sjc.id,area_setor="Produção",linha_processo="Linha 1",nome="Prensa hidráulica 001",fabricante="Fabricante A",modelo="PH-100",numero_serie="PH100",ano="2020",tipo_equipamento="Prensa",responsavel_area="Produção",criticidade="Alta",risco_maquina="Significativo",status_nr12="Não conforme",ultima_adequacao=date.today()-timedelta(days=180),ultima_auditoria=date.today()-timedelta(days=90),proxima_auditoria=date.today()+timedelta(days=40),data_prevista_adequacao=date.today()+timedelta(days=120),possui_laudo=True,possui_art=True,possui_apreciacao_risco=True,possui_manual_atualizado=True,possui_treinamento=True)
            db.add(m); db.flush()
            for t in DOCUMENTOS_ESSENCIAIS: db.add(DocumentoNR12(maquina_id=m.id,site_id=sjc.id,tipo=t,descricao=t,data_emissao=date.today()-timedelta(days=200),data_validade=date.today()+timedelta(days=365),arquivo_nome=t+".pdf",responsavel="EHS"))
            db.add(PACNR12(origem="Seed",site_id=sjc.id,maquina_id=m.id,descricao_desvio="Pendência menor em sinalização.",classificacao="Menor",responsavel="Manutenção SJC",area_responsavel="Manutenção",prazo=date.today()+timedelta(days=20),status="Em andamento"))
            db.commit()
        if db.query(AuditoriaCruzada).count()==0:
            sjc=db.query(Site).filter_by(codigo="SJC").first(); dia=db.query(Site).filter_by(codigo="DIA").first()
            a=AuditoriaCruzada(ano=date.today().year,ciclo="Ciclo 1",site_auditado_id=sjc.id,site_auditor_lider_id=dia.id,auditor_lider="Auditor EHS",data_planejada=date.today()+timedelta(days=30),status="Planejada",escopo="Auditoria cruzada seed")
            db.add(a); db.flush(); gerar_checklist_automatico_ehs(db,a.id,False); db.commit()
    finally: db.close()


def lista_paginas_permissao():
    paginas=[]
    def add(modulo, pagina, label=None):
        item=(modulo, pagina, label or pagina)
        if item not in paginas:
            paginas.append(item)
    add("home", "home", "Página inicial")
    add("ajuda", AJUDA_PAGE, AJUDA_PAGE)
    add("usuarios", "Usuários e Acessos", "Usuários e Acessos")
    add("bases", NOME_MODULO_BASES, NOME_MODULO_BASES)
    add("pendencias", NOME_MODULO_PENDENCIAS, NOME_MODULO_PENDENCIAS)
    add("pac", NOME_MODULO_PAC_UNIFICADO, NOME_MODULO_PAC_UNIFICADO)
    for modulo, home, submods in [("nr12", NR12_HOME_PAGE, NR12_SUBMODULOS),("ehs", EHS_HOME_PAGE, EHS_SUBMODULOS),("energia", ENERGIA_HOME_PAGE, ENERGIA_SUBMODULOS),("nearmiss", NEARMISS_HOME_PAGE, NEARMISS_SUBMODULOS),("legal", LEGAL_HOME_PAGE, LEGAL_SUBMODULOS),("relatorios", RELATORIOS_HOME_PAGE, RELATORIOS_SUBMODULOS)]:
        add(modulo, home, home)
        for cfg in submods.values():
            for pg in cfg.get("paginas", []): add(modulo, pg, pg)
    return paginas

def perfil_personalizado_usuario(u):
    if not u or normalizar_perfil_acesso(getattr(u, "perfil", None)) != PERFIL_PERSONALIZADO: return None
    return getattr(u, "perfil_personalizado_obj", None)

def usuario_personalizado_tem_permissao(u, modulo=None, pagina=None, tipo="visualizar"):
    perfil=perfil_personalizado_usuario(u)
    if not perfil or not getattr(perfil,"ativo",False): return False
    try:
        db_tmp=SessionLocal(); perms=db_tmp.query(PermissaoAcessoPagina).filter_by(perfil_id=perfil.id).all(); db_tmp.close()
    except Exception:
        perms=[]
    for p in perms:
        if modulo and p.modulo!=modulo: continue
        if pagina and p.pagina!=pagina: continue
        if tipo=="editar" and p.pode_editar: return True
        if tipo=="exportar" and (p.pode_exportar or p.pode_editar): return True
        if tipo=="visualizar" and (p.pode_visualizar or p.pode_editar or p.pode_exportar): return True
    return False

def is_custom_lag_user(u):
    perfil=perfil_personalizado_usuario(u)
    return bool(perfil and getattr(perfil,"visao_lag",False))

def can_admin(u): return is_master_user(u)

def can_access_page(u, modulo, pagina):
    if not u or not getattr(u,"ativo",False): return False
    if modulo in ["home","ajuda"]: return True
    if is_super_admin_user(u): return True
    if modulo in ["usuarios","bases"]: return False
    perfil=normalizar_perfil_acesso(getattr(u,"perfil",None))
    if perfil==PERFIL_PERSONALIZADO: return usuario_personalizado_tem_permissao(u,modulo,pagina,"visualizar")
    if is_master_user(u): return True
    if pagina in ["Logs do Sistema"]: return False
    return perfil in [PERFIL_TECNICO_EHS, PERFIL_VISUALIZADOR]

def can_access_module(u, modulo):
    if modulo in ["home","ajuda"]: return True
    if modulo in ["usuarios","bases"]: return is_super_admin_user(u)
    if normalizar_perfil_acesso(getattr(u,"perfil",None))==PERFIL_PERSONALIZADO:
        return usuario_personalizado_tem_permissao(u,modulo,None,"visualizar")
    return bool(u and getattr(u,"ativo",False))

def can_edit_page(u, modulo, pagina=None):
    if not u or not getattr(u,"ativo",False): return False
    if is_super_admin_user(u): return True
    if modulo in ["usuarios","bases"]: return False
    perfil=normalizar_perfil_acesso(getattr(u,"perfil",None))
    if perfil==PERFIL_PERSONALIZADO: return usuario_personalizado_tem_permissao(u,modulo,pagina,"editar") or (pagina is None and usuario_personalizado_tem_permissao(u,modulo,None,"editar"))
    if is_master_user(u): return True
    return perfil==PERFIL_TECNICO_EHS

def can_export_page(u, modulo, pagina=None):
    if not u or not getattr(u,"ativo",False): return False
    if is_master_user(u): return True
    perfil=normalizar_perfil_acesso(getattr(u,"perfil",None))
    if perfil==PERFIL_PERSONALIZADO: return usuario_personalizado_tem_permissao(u,modulo,pagina,"exportar") or (pagina is None and usuario_personalizado_tem_permissao(u,modulo,None,"exportar"))
    return perfil in [PERFIL_TECNICO_EHS, PERFIL_VISUALIZADOR]

def _ctx_to_modulo(ctx):
    c=str(ctx or "").lower()
    if any(x in c for x in ["auditoria","ehs","diretriz"]): return "ehs"
    if any(x in c for x in ["energia","emiss"]): return "energia"
    if any(x in c for x in ["near","concern"]): return "nearmiss"
    if any(x in c for x in ["legal","obrig"]): return "legal"
    if any(x in c for x in ["relatorio","ats","gensuite"]): return "relatorios"
    if any(x in c for x in ["pac","acao","ação"]): return "pac"
    return "nr12"

def can_edit(u,ctx="geral"):
    return can_edit_page(u,_ctx_to_modulo(ctx),None)

def visible_site_ids(u,db):
    if not u or not getattr(u,"ativo",False): return []
    if is_master_user(u) or is_custom_lag_user(u): return [s.id for s in db.query(Site).filter(Site.codigo!="Corporativo",Site.ativo==True).all()]
    return [u.site_id] if u.site_id else []

def visible_site_codes(u,db):
    if not u or not getattr(u,"ativo",False): return []
    if is_master_user(u) or is_custom_lag_user(u): return [s.codigo for s in db.query(Site).filter(Site.codigo!="Corporativo",Site.ativo==True).all()]
    return [u.site.codigo] if getattr(u,"site",None) and u.site.codigo!="Corporativo" else []

def filtrar_df_por_site_codigo(df, u, db, coluna_site="Site"):
    if df is None or getattr(df, "empty", True) or not u or coluna_site not in getattr(df, "columns", []):
        return df
    codigos=set(visible_site_codes(u,db))
    if not codigos:
        return df.iloc[0:0].copy()
    if is_master_user(u) or is_custom_lag_user(u):
        return df.copy()
    base=df.copy()
    serie=base[coluna_site].astype(str).str.upper().str.strip()
    return base[serie.isin({str(c).upper().strip() for c in codigos})].copy()

def filtro_site_padrao(db,u,key_prefix="filtro_site",incluir_todos=True,codigos=None):
    codigos_base=codigos or visible_site_codes(u,db)
    if not codigos_base: return []
    if len(codigos_base)==1 or not incluir_todos: return codigos_base
    opcoes=["Todos"]+codigos_base
    selecionado=st.multiselect("Site",opcoes,default=["Todos"],key=f"{key_prefix}_site")
    if not selecionado or "Todos" in selecionado: return codigos_base
    return [x for x in selecionado if x in codigos_base]

def render_filtros_padrao(db,u,df=None,key_prefix="filtro_padrao",col_site="Site",incluir_periodo=False):
    filtros={"sites":visible_site_codes(u,db),"data_inicio":None,"data_fim":None}
    cols=st.columns(3 if incluir_periodo else 1)
    op_sites=filtros["sites"]
    if df is not None and col_site in getattr(df,"columns",[]):
        op_sites=[x for x in op_sites if x in set(df[col_site].astype(str))] or filtros["sites"]
    with cols[0]: filtros["sites"]=filtro_site_padrao(db,u,key_prefix,True,op_sites)
    if incluir_periodo:
        with cols[1]: filtros["data_inicio"]=st.date_input("Data inicial",value=date.today()-timedelta(days=365),key=f"{key_prefix}_dt_ini")
        with cols[2]: filtros["data_fim"]=st.date_input("Data final",value=date.today(),key=f"{key_prefix}_dt_fim")
    return filtros


def registrar_log(db, usuario, modulo, entidade, entidade_id, acao, campo=None, valor_anterior=None, valor_novo=None, observacao=None):
    try:
        nome = usuario.nome if hasattr(usuario, "nome") else str(usuario or "Sistema")
        perfil = getattr(usuario, "perfil", None) if usuario is not None else None
        db.add(LogAuditoriaSistema(
            usuario=nome, perfil=perfil, modulo=modulo, entidade=entidade, entidade_id=entidade_id,
            acao=acao, campo=campo, valor_anterior=None if valor_anterior is None else str(valor_anterior),
            valor_novo=None if valor_novo is None else str(valor_novo), observacao=observacao, data_hora=datetime.utcnow()
        ))
    except Exception:
        logging.exception("Falha ao registrar log de auditoria do sistema")

def df_logs(db):
    rows=[]
    for l in db.query(LogAuditoriaSistema).order_by(LogAuditoriaSistema.data_hora.desc()).limit(2000):
        rows.append({
            "ID": l.id, "Data/hora": l.data_hora.strftime("%d/%m/%Y %H:%M") if l.data_hora else "—",
            "Usuário": l.usuario, "Perfil": l.perfil, "Módulo": l.modulo, "Entidade": l.entidade,
            "ID entidade": l.entidade_id, "Ação": l.acao, "Campo": l.campo,
            "Valor anterior": l.valor_anterior, "Valor novo": l.valor_novo, "Observação": l.observacao
        })
    return pd.DataFrame(rows)

def as_date(v):
    if v in (None,""): return None
    if isinstance(v,datetime): return v.date()
    if isinstance(v,date): return v
    try: return pd.to_datetime(v).date()
    except Exception: return None
def fmt_date(v): v=as_date(v); return v.strftime("%d/%m/%Y") if v else "—"
def site_nome_padrao(codigo):
    cod = normalize_site_code(codigo)
    return SITES_LAG.get(cod, {}).get("nome", str(codigo) if codigo else "—")

def site_nome_curto(codigo):
    cod = normalize_site_code(codigo)
    return SITES_LAG.get(cod, {}).get("nome_curto", str(codigo) if codigo else "—")

def site_grupo(codigo):
    cod = normalize_site_code(codigo)
    return SITES_LAG.get(cod, {}).get("grupo", "—")

def site_divisao(codigo):
    cod = normalize_site_code(codigo)
    return SITES_LAG.get(cod, {}).get("divisao", site_grupo(cod))

def site_label(codigo, formato="padrao"):
    cod = normalize_site_code(codigo)
    if formato == "curto":
        return site_nome_curto(cod)
    if formato == "grupo":
        return site_grupo(cod)
    if formato == "divisao":
        return site_divisao(cod)
    if formato == "codigo_nome":
        return f"{cod} — {site_nome_padrao(cod)}" if cod and cod != "—" else "—"
    return site_nome_padrao(cod)

def normalize_site_code(valor):
    if valor is None:
        return "—"
    raw = str(valor).strip()
    if raw in SITES_LAG:
        return raw
    norm = unicodedata.normalize("NFKD", raw).encode("ascii", "ignore").decode("ascii").lower()
    aliases = {
        "cac": ["cac", "cachoeirinha"],
        "jac": ["jac", "jacarei", "jacarei sp"],
        "jun": ["jun", "jundiai", "jundiai sp"],
        "per": ["per", "perus", "sao paulo", "sao paulo bra"],
        "sjc": ["sjc", "sao jose dos campos", "sao jose"],
        "dia": ["dia", "diadema", "diadema sp"],
        "corporativo": ["corporativo", "corp", "lag"],
    }
    for cod, pats in aliases.items():
        if any(p in norm for p in pats):
            return cod.upper() if cod != "corporativo" else "Corporativo"
    return raw
def site_code(db,id):
    s=db.get(Site,id) if id else None
    return site_label(s.codigo) if s else "—"
def machine_options(db,ids): return {f"{m.codigo} — {m.nome}":m.id for m in db.query(MaquinaNR12).filter(MaquinaNR12.site_id.in_(ids)).order_by(MaquinaNR12.codigo)}
def identificar_pac_vencido(prazo,status): return bool(as_date(prazo) and as_date(prazo)<date.today() and status not in ["Concluída","Cancelada"])


def ats_headers_unicos(headers=None):
    """Retorna cabeçalhos únicos apenas para pré-visualização.

    O template ATS possui cabeçalhos repetidos, como Closure Due Date.
    O DataFrame de exportação mantém os nomes originais, mas a prévia do Streamlit
    precisa de nomes únicos. Não use ``headers or ...`` aqui porque ``headers`` pode
    ser um pandas.Index, cuja avaliação booleana gera ValueError.
    """
    base = ATS_TEMPLATE_HEADERS if headers is None else list(headers)
    vistos = {}
    saida = []
    for h in base:
        h = str(h)
        vistos[h] = vistos.get(h, 0) + 1
        saida.append(h if vistos[h] == 1 else f"{h} ({vistos[h]})")
    return saida

