def ats_codigo_diretriz(texto):
    m = re.search(r"4\.12\.\d{2}", str(texto or ""))
    return m.group(0) if m else ""

def ats_categoria_por_diretriz_texto(texto, fallback=None):
    codigo = ats_codigo_diretriz(texto)
    return ATS_EHS_CATEGORY_BY_DIRECTIVE.get(codigo, fallback or ATS_CATEGORIA_EHS_DEFAULT)

def ats_normalizar_dept(area):
    val = str(area or "").strip()
    if not val or val in ["—", "A definir", "N/A", "Não definido"]:
        return "EHS"
    mapa = {
        "manutenção": "Maintenance", "manutencao": "Maintenance",
        "engenharia": "Engineering", "produção": "Production", "producao": "Production",
        "operações": "Operations", "operacoes": "Operations", "operação": "Operations", "operacao": "Operations",
        "facilities": "Facilities", "almoxarifado": "Warehouse", "armazém": "Warehouse", "armazem": "Warehouse",
        "qualidade": "Quality", "logística": "Logistics", "logistica": "Logistics",
        "recebimento": "Receiving", "expedição": "Shipping", "expedicao": "Shipping",
        "ehs": "EHS", "segurança": "EHS", "seguranca": "EHS", "hse": "EHS",
    }
    chave = unicodedata.normalize("NFKD", val).encode("ascii", "ignore").decode("ascii").lower()
    return mapa.get(chave, val)

def ats_add_current_value(options, value):
    opts = [str(x) for x in (options or []) if str(x or "").strip()]
    val = "" if value is None else str(value).strip()
    if val and val not in opts:
        opts = [val] + opts
    return opts or [""]

def ats_select_index(options, value=None, default_value=None):
    opts = ats_add_current_value(options, value if value not in [None, ""] else default_value)
    alvo = str(value if value not in [None, ""] else (default_value or "")).strip()
    idx = opts.index(alvo) if alvo in opts else 0
    return opts, idx

def ats_selectbox(label, options, value=None, key=None, default_value=None, container=None, help=None):
    opts, idx = ats_select_index(options, value, default_value)
    c = container or st
    return c.selectbox(label, opts, index=idx, key=key, help=help)

def ats_contact_selectbox(label, value=None, key=None, container=None, required=False):
    contatos = ats_options("ResponsiblePerson")
    if not contatos:
        contatos = ATS_FALLBACK_OPTIONS.get("ResponsiblePerson", [])
    opts = ats_add_current_value(contatos, value)
    if not required and "" not in opts:
        opts = [""] + opts
    val = "" if value is None else str(value).strip()
    idx = opts.index(val) if val in opts else 0
    c = container or st
    return c.selectbox(label, opts, index=idx, key=key)

def ats_status_from_pac(status):
    return ATS_STATUS_FROM_PAC.get(str(status or "").strip(), "Open")

def ats_risk_from_priority(valor):
    return ATS_RISCO_FROM_CLASSIFICACAO.get(str(valor or "").strip(), "Medium")

def ats_app_status_from_ats(valor, atual=None):
    val = str(valor or "").strip()
    if val == "Closed":
        return "Concluída"
    if atual in ["Aberta", "Em andamento", "Aguardando validação", "Vencida"]:
        return atual
    return "Aberta"

def ats_app_priority_from_risk(valor, atual=None):
    mapa = {"High": "Crítico", "Medium": "Maior", "Low": "Menor", "Evaluation": "Menor", "Recommended Practice": "Menor"}
    if atual in CLASSIFICACAO_PAC:
        return atual
    return mapa.get(str(valor or "").strip(), "Maior")

def ats_closure_category_from_dates(data_base=None, prazo=None):
    base = as_date(data_base) or date.today()
    due = as_date(prazo)
    if not due:
        return "30 day"
    dias = max(0, (due - base).days)
    if dias <= 1: return "1 day"
    if dias <= 3: return "3 day"
    if dias <= 5: return "5 day"
    if dias <= 7: return "7 day"
    if dias <= 15: return "15 day"
    if dias <= 30: return "30 day"
    if dias <= 60: return "60 day"
    if dias <= 90: return "90 day"
    return ">90 day"

def ats_due_date_from_closure(action_date=None, closure_category=None, custom_due=None):
    base = as_date(action_date) or date.today()
    cat = str(closure_category or "30 day").strip()
    if cat.startswith(">"):
        return as_date(custom_due)
    m = re.match(r"(\d+)", cat)
    dias = int(m.group(1)) if m else 30
    return base + timedelta(days=dias)

def ats_group_default(site_codigo):
    return ATS_SITE_TO_GROUP.get(normalize_site_code(site_codigo), ATS_GROUP_OPTIONS[0] if ATS_GROUP_OPTIONS else "")

def ats_business_unit_default(site_codigo):
    return ATS_SITE_TO_BUSINESS_UNIT.get(normalize_site_code(site_codigo), str(site_codigo or ""))

def ats_defaults_genericos(db, site_id=None, titulo="", descricao="", acao="", responsavel="", area="", prazo=None, status="Aberta", categoria=None, prioridade=None, origem=None, finding_element="", finding_citations="", reference_id="", investigation_details="", root_cause=""):
    site = db.get(Site, site_id) if site_id else None
    site_codigo = site.codigo if site else None
    data_base = date.today()
    due = as_date(prazo) or (date.today() + timedelta(days=30))
    closure_cat = ats_closure_category_from_dates(data_base, due)
    risco = ats_risk_from_priority(prioridade)
    return {
        "ats_group": ats_group_default(site_codigo),
        "ats_business_unit": ats_business_unit_default(site_codigo),
        "ats_action_title": titulo or "Ação corretiva EHS",
        "ats_action_date": data_base,
        "ats_audit_action_type": origem or "Standards / Directives",
        "ats_action_type": "Risk Management",
        "ats_action_category": categoria or ATS_CATEGORIA_EHS_DEFAULT,
        "ats_finding_element": finding_element or "EHS",
        "ats_finding_citations": finding_citations or "",
        "ats_number_items": 1,
        "ats_repeat_action": "No",
        "ats_risk_category": risco,
        "ats_closure_category": closure_cat,
        "ats_department": ats_normalizar_dept(area),
        "ats_subdepartment": "",
        "ats_building": ats_business_unit_default(site_codigo) or "Main Building",
        "ats_workstation": "Plant Wide",
        "ats_responsible_person": responsavel or "",
        "ats_action_description": descricao or "",
        "ats_corrective_action": acao or "A definir",
        "ats_auditor_contact": "",
        "ats_phone": "",
        "ats_closure_due_date": due,
        "ats_closure_due_date_gt90": due if closure_cat == ">90 day" else None,
        "ats_status": ats_status_from_pac(status),
        "ats_close_date": None,
        "ats_close_comment": "",
        "ats_closure_person": "",
        "ats_finding_reference_type": "Internal Audit",
        "ats_reference_id": reference_id or "",
        "ats_multiple_email_cc": "",
        "ats_closure_verification_person": "",
        "ats_closure_verification_due_date": due + timedelta(days=7),
        "ats_reminder_email_days_prior": "7",
        "ats_capa_required": "Yes" if risco == "High" else "No",
        "ats_investigation_details": investigation_details or "",
        "ats_root_cause": root_cause or "",
        "ats_basic_root_cause": "",
        "ats_near_root_cause": "",
    }

def ats_attr(obj, field, default=None):
    val = getattr(obj, field, None) if obj is not None else None
    return default if val in [None, ""] else val

def ats_payload_from_obj(db, obj, defaults=None):
    defaults = defaults or {}
    payload = {}
    for f in ATS_DB_FIELDS:
        payload[f] = ats_attr(obj, f, defaults.get(f))
    return payload

def aplicar_campos_ats(obj, dados):
    for f in ATS_DB_FIELDS:
        if f in dados:
            setattr(obj, f, dados.get(f))

def ats_sync_legacy_fields(obj, dados, modulo=""):
    """Mantém os campos antigos do app preenchidos a partir do cadastro único ATS."""
    if isinstance(obj, PACNR12):
        obj.descricao_desvio = dados.get("ats_action_description") or obj.descricao_desvio
        obj.comentarios = dados.get("ats_corrective_action") or obj.comentarios
        obj.responsavel = dados.get("ats_responsible_person") or obj.responsavel
        obj.area_responsavel = dados.get("ats_department") or obj.area_responsavel
        obj.prazo = dados.get("ats_closure_due_date") or obj.prazo
        obj.status = ats_app_status_from_ats(dados.get("ats_status"), obj.status)
        obj.classificacao = ats_app_priority_from_risk(dados.get("ats_risk_category"), obj.classificacao)
        obj.evidencia_conclusao = dados.get("ats_close_comment") or obj.evidencia_conclusao
        obj.data_conclusao = dados.get("ats_close_date") or obj.data_conclusao
        obj.verificacao_eficacia = dados.get("ats_investigation_details") or obj.verificacao_eficacia
    elif isinstance(obj, PACEHS):
        obj.descricao = dados.get("ats_action_description") or obj.descricao
        obj.acao_corretiva = dados.get("ats_corrective_action") or obj.acao_corretiva
        obj.responsavel = dados.get("ats_responsible_person") or obj.responsavel
        obj.area_responsavel = dados.get("ats_department") or obj.area_responsavel
        obj.prazo = dados.get("ats_closure_due_date") or obj.prazo
        obj.status = ats_app_status_from_ats(dados.get("ats_status"), obj.status)
        obj.prioridade_criticidade = {"Crítico":"Alta", "Maior":"Média", "Menor":"Baixa"}.get(ats_app_priority_from_risk(dados.get("ats_risk_category")), obj.prioridade_criticidade or "Média")
        obj.tipo_achado = obj.tipo_achado or "Não conformidade maior"
        obj.risco = dados.get("ats_risk_category") or obj.risco
        obj.causa_raiz = dados.get("ats_root_cause") or obj.causa_raiz
        obj.evidencia = dados.get("ats_finding_citations") or obj.evidencia
        obj.acao_imediata = dados.get("ats_investigation_details") or obj.acao_imediata
        obj.evidencia_conclusao = dados.get("ats_close_comment") or obj.evidencia_conclusao
        obj.data_conclusao = dados.get("ats_close_date") or obj.data_conclusao

def ats_is_blank(v):
    if v is None:
        return True
    if isinstance(v, str) and not v.strip():
        return True
    return False

def ats_validate_payload(dados):
    faltantes = []
    for f in ATS_REQUIRED_BASE_FIELDS:
        if ats_is_blank(dados.get(f)):
            faltantes.append(ATS_FIELD_TO_HEADER.get(f, f))
    if str(dados.get("ats_closure_category") or "").startswith(">") and ats_is_blank(dados.get("ats_closure_due_date_gt90")):
        faltantes.append("Closure Due Date (>90 day)")
    if dados.get("ats_status") == "Closed":
        for f in ATS_CLOSED_REQUIRED_FIELDS:
            if ats_is_blank(dados.get(f)):
                faltantes.append(ATS_FIELD_TO_HEADER.get(f, f))
    if faltantes:
        st.error("Preencha os campos obrigatórios do template Gensuite: " + ", ".join(faltantes))
        return False
    return True

def ats_optional_date(container, label, value=None, key=None):
    atual = as_date(value)
    usar = container.checkbox(f"Informar {label}", value=bool(atual), key=f"{key}_usar")
    if not usar:
        return None
    return container.date_input(label, atual or date.today(), key=key)

def _render_ats_fields_body(prefix, defaults=None, show_optional=True):
    d = defaults or {}
    dados = {}
    st.caption("Preencha a ação diretamente no padrão do template ATS/Gensuite. Os campos marcados como obrigatórios seguem a própria planilha de upload.")
