    c1, c2, c3 = st.columns(3)
    dados["ats_group"] = ats_selectbox("Group *", ATS_GROUP_OPTIONS, d.get("ats_group"), key=f"{prefix}_ats_group", container=c1)
    dados["ats_business_unit"] = ats_selectbox("Business Unit *", ATS_BRAZIL_SITE_OPTIONS, d.get("ats_business_unit"), key=f"{prefix}_ats_business_unit", container=c2)
    dados["ats_action_date"] = c3.date_input("Action Date *", as_date(d.get("ats_action_date")) or date.today(), key=f"{prefix}_ats_action_date")

    c1, c2, c3 = st.columns(3)
    dados["ats_audit_action_type"] = ats_selectbox("Audit/Action Type *", ATS_AUDIT_TYPE_OPTIONS, d.get("ats_audit_action_type"), key=f"{prefix}_ats_audit_action_type", container=c1)
    dados["ats_action_type"] = ats_selectbox("Action Type *", ATS_ACTION_TYPE_OPTIONS, d.get("ats_action_type"), key=f"{prefix}_ats_action_type", container=c2)
    dados["ats_action_category"] = ats_selectbox("Action Category *", ATS_CATEGORY_OPTIONS, d.get("ats_action_category"), key=f"{prefix}_ats_action_category", container=c3)

    c1, c2, c3, c4 = st.columns(4)
    dados["ats_number_items"] = int(c1.number_input("Number of Items in Action *", min_value=1, value=int(d.get("ats_number_items") or 1), step=1, key=f"{prefix}_ats_number_items"))
    dados["ats_repeat_action"] = ats_selectbox("Repeat Action? *", ATS_YES_NO_OPTIONS, d.get("ats_repeat_action"), key=f"{prefix}_ats_repeat_action", container=c2, default_value="No")
    dados["ats_risk_category"] = ats_selectbox("Risk Category *", ATS_RISK_CATEGORY_OPTIONS, d.get("ats_risk_category"), key=f"{prefix}_ats_risk_category", container=c3, default_value="Medium")
    dados["ats_closure_category"] = ats_selectbox("Closure Category *", ATS_CLOSURE_CATEGORY_OPTIONS, d.get("ats_closure_category"), key=f"{prefix}_ats_closure_category", container=c4, default_value="30 day")

