            dados["ats_finding_citations"] = c3.text_input("Finding Citation(s)", value=str(d.get("ats_finding_citations") or ""), key=f"{prefix}_ats_finding_citations")
            c1, c2, c3 = st.columns(3)
            dados["ats_subdepartment"] = ats_selectbox("Sub-Dept", ATS_SUBDEPT_OPTIONS, d.get("ats_subdepartment"), key=f"{prefix}_ats_subdepartment", container=c1)
            dados["ats_building"] = ats_selectbox("Building", ATS_BUILDING_OPTIONS, d.get("ats_building"), key=f"{prefix}_ats_building", container=c2, default_value="Plant Wide")
            dados["ats_workstation"] = c3.text_input("Workstation", value=str(d.get("ats_workstation") or "Plant Wide"), key=f"{prefix}_ats_workstation")
            c1, c2, c3 = st.columns(3)
            dados["ats_auditor_contact"] = ats_contact_selectbox("Auditor/Contact", d.get("ats_auditor_contact"), key=f"{prefix}_ats_auditor_contact", container=c1, required=False)
            dados["ats_phone"] = c2.text_input("Phone", value=str(d.get("ats_phone") or ""), key=f"{prefix}_ats_phone")
            dados["ats_multiple_email_cc"] = c3.text_input("Multiple Email CC", value=str(d.get("ats_multiple_email_cc") or ""), key=f"{prefix}_ats_multiple_email_cc", help="Lista separada por vírgulas, quando houver.")
            c1, c2, c3 = st.columns(3)
