def ultima_atualizacao_modulo(db, modulo):
    try:
        if modulo == "energia":
            h = db.query(EnergiaUploadHistorico).order_by(EnergiaUploadHistorico.data_upload.desc()).first()
        elif modulo == "nearmiss":
            h = db.query(NearMissUploadHistorico).order_by(NearMissUploadHistorico.data_upload.desc()).first()
        elif modulo == "legal":
            h = db.query(LegalUploadHistorico).order_by(LegalUploadHistorico.data_upload.desc()).first()
        elif modulo == "ehs":
            h = db.query(ProcedimentoAltoRiscoUploadHistorico).order_by(ProcedimentoAltoRiscoUploadHistorico.data_upload.desc()).first()
        else:
            h = None
        if not h or not h.data_upload:
            return "Sem atualização registrada"
        return h.data_upload.strftime("%d/%m/%Y %H:%M")
    except Exception:
        return "Indisponível"

def mostrar_ultima_atualizacao_modulo(db, modulo, u, local="main"):
    if can_update_bases(u):
        return
    texto = f"Última atualização da base: {ultima_atualizacao_modulo(db, modulo)}"
    if local == "sidebar":
        st.sidebar.caption(texto)
    else:
        st.caption(texto)

def submodulos_visiveis(modulo, u):
    base = {
        "nr12": NR12_SUBMODULOS,
        "ehs": EHS_SUBMODULOS,
        "energia": ENERGIA_SUBMODULOS,
        "nearmiss": NEARMISS_SUBMODULOS,
        "legal": LEGAL_SUBMODULOS,
        "relatorios": RELATORIOS_SUBMODULOS,
    }.get(modulo, {})
    paginas_centralizadas = {"Atualizar Base", "Actual Hours", "Atualizar Base Near Miss", "Atualizar Base Legal", "Atualizar Procedimentos de Alto Risco"}
    out = {}
    for nome, cfg in base.items():
        paginas = []
        for p in cfg.get("paginas", []):
            if p in paginas_centralizadas:
                continue
            if p == "Logs do Sistema" and not can_admin(u):
                continue
            if can_access_page(u, modulo, p):
                paginas.append(p)
        if paginas:
            novo = dict(cfg)
            novo["paginas"] = paginas
            out[nome] = novo
    return out


def bases_status_df(db):
    """Resumo simples das últimas cargas registradas por base oficial."""
    linhas = []
    def add(modulo, base, tabela_cls=None, hist_cls=None, extra_filter=None):
        ultima = ultima_atualizacao_modulo(db, modulo)
        total = None
        try:
            if tabela_cls is not None:
                q = db.query(tabela_cls)
                if extra_filter is not None:
                    q = extra_filter(q)
                total = q.count()
        except Exception:
            total = None
        linhas.append({
            "Módulo": modulo,
            "Base": base,
            "Registros atuais": "—" if total is None else int(total),
            "Última atualização": ultima,
        })
    add("energia", "Energia, gás e emissões", EnergiaRegistro)
    add("energia", "Actual Hours", EnergiaActualHours)
    add("nearmiss", "Concern Reports / Near Miss", NearMissRegistro)
    add("legal", "Legislação e Obrigações", LegalRegistro)
    add("ehs", "Procedimentos de Alto Risco", ProcedimentoAltoRiscoRegistro)
    return pd.DataFrame(linhas)

