    if can_edit(u,"pac_ehs") and not df.empty:
        with st.expander("Editar ação corretiva", expanded=False):
            pac_id=int(st.selectbox("Selecionar ação/PAC",df["ID"].astype(int).tolist(),key="ehs_pac_update_select"))
            p=db.get(PACEHS,pac_id)
            if p:
                with st.form("edit_pac_ehs_ats_unificado"):
                    req = getattr(p, "requisito", None)
                    diretriz_txt = getattr(getattr(req, "diretiva", None), "categoria", "") if req else ""
