def ehs_base_checklist(db,u):
    header("Base do Checklist EHS","Checklist sintético baseado nas Diretrizes Globais de EHS 4.12, editável e versionado")
    if not can_edit(u,"auditoria"):
        alert_card("Seu perfil permite consulta, mas não administração da base de checklists.")
    versao_ativa = db.query(ChecklistVersaoEHS).filter_by(ativo=True).order_by(ChecklistVersaoEHS.versao.desc(), ChecklistVersaoEHS.id.desc()).first()
    c1,c2,c3 = st.columns(3)
    with c1:
        kpi_card("Versão ativa", f"v{versao_ativa.versao}" if versao_ativa else "—", "Novas auditorias usarão esta versão")
    with c2:
        kpi_card("Requisitos ativos", db.query(RequisitoEHS).filter_by(ativo=True).count(), "Base editável atual")
    with c3:
        kpi_card("Diretrizes", db.query(DiretivaEHS).filter_by(ativo=True).count(), "Categorias do checklist")

    section("Como funciona")
    st.caption("Os checklists padrão continuam dentro do código como carga inicial. Depois que o banco é criado, a base passa a ser editável pelo app; as alterações ficam salvas no banco e novas auditorias recebem snapshots da versão ativa.")

    reqs=db.query(RequisitoEHS).join(DiretivaEHS).filter(RequisitoEHS.ativo==True,DiretivaEHS.ativo==True).order_by(DiretivaEHS.categoria,RequisitoEHS.ordem).all()
    df=pd.DataFrame([{"ID":r.id,"Diretriz":r.diretiva.categoria,"Ordem":r.ordem,"Requisito":r.pergunta,"Ativo":r.ativo,"Criticidade":r.criticidade,"Evidência esperada":r.evidencia_esperada,"Gerar PAC automático":getattr(r,"gera_pac_automatico",False)} for r in reqs])
    if can_edit(u,"auditoria"):
        section("Editar base atual")
        ed=st.data_editor(
            df,
            use_container_width=True,
            hide_index=True,
            disabled=["ID"],
            column_config={"Criticidade":st.column_config.SelectboxColumn("Criticidade",options=CRITICIDADES)},
            key="editor_base_checklist_ehs_editavel",
        )
        csave,cversion = st.columns(2)
        with csave:
            if st.button("Salvar base e criar nova versão ativa",use_container_width=True):
                for _,row in ed.iterrows():
                    r=db.get(RequisitoEHS,int(row["ID"]))
                    if not r:
                        continue
                    categoria=str(row["Diretriz"]).strip() or "Sem diretriz"
                    d=db.query(DiretivaEHS).filter_by(categoria=categoria).first()
                    if not d:
                        d=DiretivaEHS(categoria=categoria,descricao=categoria,ativo=True); db.add(d); db.flush()
                    r.diretiva_id=d.id
                    r.ordem=int(row["Ordem"]) if pd.notna(row["Ordem"]) else r.ordem
                    r.pergunta=str(row["Requisito"]).strip()
                    r.ativo=bool(row["Ativo"])
                    r.criticidade=row["Criticidade"] if row["Criticidade"] in CRITICIDADES else "Média"
                    r.evidencia_esperada=row["Evidência esperada"]
                    r.gera_pac_automatico=bool(row.get("Gerar PAC automático", False))
                nova = criar_versao_checklist_ehs(db,u.nome,"Versão criada após edição da base EHS")
                registrar_log(db,u,"Auditoria Cruzada","ChecklistVersaoEHS",nova.id,"criar",observacao="Base EHS editada e nova versão ativa criada")
                db.commit(); st.success(f"Base atualizada. Nova versão ativa criada: v{nova.versao}."); st.rerun()
        with cversion:
            if st.button("Criar nova versão sem alterar a base",use_container_width=True):
                nova = criar_versao_checklist_ehs(db,u.nome,"Nova versão criada manualmente a partir da base atual")
                registrar_log(db,u,"Auditoria Cruzada","ChecklistVersaoEHS",nova.id,"criar",observacao="Nova versão EHS criada a partir da base atual")
                db.commit(); st.success(f"Nova versão ativa criada: v{nova.versao}."); st.rerun()
        with st.expander("Criar novo requisito EHS"):
            cats = [d.categoria for d in db.query(DiretivaEHS).order_by(DiretivaEHS.categoria).all()]
            with st.form("novo_requisito_ehs"):
                modo_cat = st.radio("Diretriz", ["Usar existente", "Criar nova"], horizontal=True)
                if modo_cat == "Usar existente" and cats:
                    categoria = st.selectbox("Diretriz existente", cats)
                else:
                    categoria = st.text_input("Nova diretriz")
                ordem = st.number_input("Ordem", min_value=1, value=1)
                pergunta = st.text_area("Requisito / pergunta")
                criticidade = st.selectbox("Criticidade", CRITICIDADES)
                evidencia = st.text_area("Evidência esperada")
                pac_auto = st.checkbox("Gerar PAC automático quando houver não conformidade")
                if st.form_submit_button("Adicionar requisito e criar nova versão", use_container_width=True):
                    if not pergunta.strip() or not categoria.strip():
                        st.error("Informe diretriz e requisito/pergunta.")
                    else:
                        d = db.query(DiretivaEHS).filter_by(categoria=categoria.strip()).first()
                        if not d:
                            d = DiretivaEHS(categoria=categoria.strip(), descricao=categoria.strip(), ativo=True); db.add(d); db.flush()
                        obj = RequisitoEHS(diretiva_id=d.id, ordem=int(ordem), pergunta=pergunta.strip(), criticidade=criticidade, evidencia_esperada=evidencia, gera_pac_automatico=pac_auto, ativo=True)
                        db.add(obj); db.flush()
                        nova = criar_versao_checklist_ehs(db,u.nome,"Versão criada após inclusão de requisito EHS")
                        registrar_log(db,u,"Auditoria Cruzada","RequisitoEHS",obj.id,"criar",observacao=f"Novo requisito EHS cadastrado e v{nova.versao} criada")
                        db.commit(); st.success(f"Requisito criado. Nova versão ativa: v{nova.versao}."); st.rerun()
    else:
        st.dataframe(df,use_container_width=True,hide_index=True)

    section("Versões EHS cadastradas")
    versoes = db.query(ChecklistVersaoEHS).order_by(ChecklistVersaoEHS.versao.desc(), ChecklistVersaoEHS.id.desc()).all()
    dfv = pd.DataFrame([{"ID":v.id,"Versão":v.versao,"Ativo":v.ativo,"Criado por":v.criado_por,"Criado em":fmt_date(v.criado_em),"Descrição":v.descricao} for v in versoes])
    st.dataframe(dfv, use_container_width=True, hide_index=True)
    download_excel_button("Exportar base do checklist EHS", "base_checklist_ehs.xlsx", {"Base_Atual": df, "Versoes": dfv})


def ehs_codigo_diretriz(categoria):
    """Extrai a tag curta da diretriz para uso em telas, Excel e PDF."""
    txt = str(categoria or "Diretriz EHS")
    m = re.search(r"4\.12\.\d{2}", txt)
    return m.group(0) if m else "EHS"


def ehs_assunto_diretriz(categoria):
    txt = str(categoria or "Diretriz EHS").strip()
    return txt.split("—", 1)[1].strip() if "—" in txt else txt


def ehs_modalidade_verificacao(pergunta="", categoria="", evidencia=""):
    """Classifica a forma preferencial de verificação do item.

    Online: documentos, registros, indicadores, evidências sistêmicas e entrevistas remotas.
    In loco: condição física, comportamento operacional, inspeção de área/equipamento ou validação visual.
    """
    txt = _ehs_norm_question(" ".join([str(pergunta or ""), str(categoria or ""), str(evidencia or "")]))
    in_loco_kw = [
        "in loco", "campo", "area", "posto", "layout", "rota", "saida", "egresso", "extintor", "sinalizacao",
        "armazen", "conten", "tanque", "dreno", "ventilacao", "iluminacao", "ruido", "temperatura", "derram",
        "maquina", "equipamento", "protec", "intertrav", "sensor", "cortina", "emergencia", "loto", "bloqueio",
        "rack", "doca", "level pad", "empilhadeira", "paleteira", "talha", "ponte", "carga", "movimentacao",
        "epi", "uso de epi", "operador", "contratado", "visitante", "quimico", "residuo", "fispq", "sds",
        "trabalho em altura", "trabalho a quente", "espaco confinado", "eletricidade energizada", "manutencao"
    ]
    online_kw = [
        "registro", "document", "procedimento", "politica", "matriz", "treinamento", "certificado", "licenca", "licenciamento",
        "indicador", "metrica", "relatorio", "ata", "business review", "revisao", "plano", "pac", "acao", "causa raiz",
        "inventario", "cadastro", "evidencia", "aprovacao", "moc", "investigacao", "tendencia", "responsavel", "prazo"
    ]
    if any(k in txt for k in in_loco_kw):
        return "In loco"
    if any(k in txt for k in online_kw):
        return "Online"
    return "Online"


def ehs_checklist_base_df(db, somente_ativo=True):
    """Retorna o checklist EHS atualmente ativo, já no formato usado por Excel e relatórios."""
    versao = db.query(ChecklistVersaoEHS).filter_by(ativo=True).order_by(ChecklistVersaoEHS.versao.desc(), ChecklistVersaoEHS.id.desc()).first()
    rows = []
    if versao:
        q = db.query(ChecklistPerguntaVersaoEHS).filter_by(checklist_versao_id=versao.id)
        if somente_ativo:
            q = q.filter(ChecklistPerguntaVersaoEHS.ativo == True)
        perguntas = q.order_by(ChecklistPerguntaVersaoEHS.categoria, ChecklistPerguntaVersaoEHS.ordem).all()
        for idx, p in enumerate(perguntas, 1):
            rows.append({
                "Nº": idx,
                "Versão": f"v{versao.versao}",
                "Diretriz": p.categoria,
                "Tag": ehs_codigo_diretriz(p.categoria),
                "Assunto": ehs_assunto_diretriz(p.categoria),
                "Ordem na diretriz": p.ordem,
                "Pergunta": p.pergunta,
                "Criticidade": p.criticidade,
                "Modalidade sugerida": ehs_modalidade_verificacao(p.pergunta, p.categoria, p.evidencia_esperada),
                "Evidência esperada": p.evidencia_esperada,
                "Ativo": "Sim" if p.ativo else "Não",
            })
    else:
        reqs = db.query(RequisitoEHS).join(DiretivaEHS).filter(RequisitoEHS.ativo==True, DiretivaEHS.ativo==True).order_by(DiretivaEHS.categoria, RequisitoEHS.ordem).all()
        for idx, r in enumerate(reqs, 1):
            cat = r.diretiva.categoria if r.diretiva else "Diretriz EHS"
            rows.append({
                "Nº": idx,
                "Versão": "Base ativa",
                "Diretriz": cat,
                "Tag": ehs_codigo_diretriz(cat),
                "Assunto": ehs_assunto_diretriz(cat),
                "Ordem na diretriz": r.ordem,
                "Pergunta": r.pergunta,
                "Criticidade": r.criticidade,
                "Modalidade sugerida": ehs_modalidade_verificacao(r.pergunta, cat, r.evidencia_esperada),
                "Evidência esperada": r.evidencia_esperada,
                "Ativo": "Sim" if r.ativo else "Não",
            })
    return pd.DataFrame(rows)


def ehs_respostas_auditoria_df(db, auditoria):
    """Monta a base completa do relatório da auditoria, usando snapshots e o checklist atual."""
    if auditoria is None:
        return pd.DataFrame()
    gerar_checklist_automatico_ehs(db, auditoria.id)
    res = db.query(RespostaAuditoriaEHS).join(RequisitoEHS).join(DiretivaEHS).filter(
        RespostaAuditoriaEHS.auditoria_id == auditoria.id,
        RequisitoEHS.ativo == True,
        DiretivaEHS.ativo == True,
    ).order_by(DiretivaEHS.categoria, RequisitoEHS.ordem).all()
    rows = []
    for idx, r in enumerate(res, 1):
        cat = r.requisito.diretiva.categoria if r.requisito and r.requisito.diretiva else "Diretriz EHS"
        pergunta = getattr(r, "pergunta_snapshot", None) or (r.requisito.pergunta if r.requisito else "Pergunta sem texto cadastrado")
        evidencia_esperada = getattr(r, "evidencia_esperada_snapshot", None) or (r.requisito.evidencia_esperada if r.requisito else "")
        status = "Não aplicável" if not r.aplicavel else (r.status or "Conforme")
        rows.append({
            "Nº": idx,
            "Tag": ehs_codigo_diretriz(cat),
            "Diretriz": cat,
            "Assunto": ehs_assunto_diretriz(cat),
            "Pergunta": pergunta,
            "Criticidade": getattr(r, "criticidade_snapshot", None) or (r.requisito.criticidade if r.requisito else "Média"),
            "Modalidade": ehs_modalidade_verificacao(pergunta, cat, evidencia_esperada),
            "Aplicável": "Sim" if r.aplicavel else "Não",
            "Status": status,
            "Maturidade": float(r.nota_maturidade or 0),
            "PAC": "Sim" if r.necessita_pac else "Não",
            "Evidência esperada": evidencia_esperada,
            "Evidência verificada": r.evidencia_verificada or "—",
            "Comentário": r.comentario_auditor or "—",
        })
    return pd.DataFrame(rows)


def ehs_resumo_diretriz_df(df):
    if df is None or df.empty:
        return pd.DataFrame()
    base = df[df["Aplicável"] == "Sim"].copy()
    if base.empty:
        return pd.DataFrame()
    def _pontua(s):
        if s == "Conforme": return 1.0
        if s == "Parcialmente Conforme": return 0.5
        if s == "Não Conforme": return 0.0
        return None
    base["Pontos"] = base["Status"].apply(_pontua)
    resumo = base.groupby(["Tag", "Assunto"], as_index=False).agg(
        Itens=("Nº", "count"),
        Conformes=("Status", lambda x: int((x == "Conforme").sum())),
        Parciais=("Status", lambda x: int((x == "Parcialmente Conforme").sum())),
        Nao_conformes=("Status", lambda x: int((x == "Não Conforme").sum())),
        Maturidade_media=("Maturidade", "mean"),
        Pontos=("Pontos", "sum"),
    )
    resumo["Conformidade %"] = (resumo["Pontos"] / resumo["Itens"] * 100).round(1)
    resumo = resumo.drop(columns=["Pontos"]).rename(columns={"Nao_conformes": "Não conformes", "Maturidade_media": "Maturidade média"})
    return resumo.sort_values(["Tag"]).reset_index(drop=True)


def gerar_pdf_auditoria_ehs(auditoria, df_itens, df_pacs, usuario="—"):
    """PDF próprio da Auditoria Cruzada, alinhado ao checklist corrido de 80 questões."""
    buf = io.BytesIO()
    doc = SimpleDocTemplate(buf, pagesize=landscape(A4), rightMargin=0.85*cm, leftMargin=0.85*cm, topMargin=0.85*cm, bottomMargin=0.85*cm)
    stl = relatorios_pdf_style()
    story = []
    data_ref = datetime.now().strftime("%d/%m/%Y %H:%M")
    titulo = f"Relatório de Auditoria Cruzada de Diretrizes EHS"
    story.append(Paragraph(html_escape(relatorios_pdf_safe_text(titulo)), stl["title"]))
    story.append(Paragraph(f"Emissão: {data_ref} | Usuário: {html_escape(relatorios_pdf_safe_text(usuario))}", stl["sub"]))

    if df_itens is None or df_itens.empty:
        story.append(Paragraph("Sem itens de checklist para a auditoria selecionada.", stl["body"]))
        doc.build(story)
        return buf.getvalue()

    total = len(df_itens)
    aplicaveis = int((df_itens["Aplicável"] == "Sim").sum())
    nc = int((df_itens["Status"] == "Não Conforme").sum())
    parciais = int((df_itens["Status"] == "Parcialmente Conforme").sum())
    pacs = int((df_itens["PAC"] == "Sim").sum())
    story.append(Paragraph("Resumo da auditoria", stl["h"]))
    dados = pd.DataFrame([{
        "Ano": auditoria.ano,
        "Ciclo": auditoria.ciclo,
        "Status": auditoria.status,
        "Itens": total,
        "Aplicáveis": aplicaveis,
        "Parciais": parciais,
        "Não conformes": nc,
        "PACs": pacs,
    }])
    story.append(relatorios_pdf_tabela([list(dados.columns)] + dados.astype(str).values.tolist(), col_widths=[1.5*cm, 3.0*cm, 2.5*cm, 1.5*cm, 1.8*cm, 1.8*cm, 2.2*cm, 1.5*cm], align_center_cols=list(range(len(dados.columns)))))

    resumo = ehs_resumo_diretriz_df(df_itens)
    story.append(Spacer(1, 0.15*cm))
    story.append(Paragraph("Resultado por diretriz", stl["h"]))
    if resumo.empty:
        story.append(Paragraph("Sem itens aplicáveis para consolidar por diretriz.", stl["body"]))
    else:
        resumo_pdf = resumo[["Tag", "Assunto", "Itens", "Conformidade %", "Maturidade média", "Não conformes"]].copy()
        resumo_pdf["Conformidade %"] = resumo_pdf["Conformidade %"].apply(lambda x: relatorios_fmt_pct(x))
        resumo_pdf["Maturidade média"] = resumo_pdf["Maturidade média"].apply(lambda x: relatorios_fmt_num(x, 2))
        story.append(relatorios_pdf_tabela([list(resumo_pdf.columns)] + resumo_pdf.astype(str).values.tolist(), col_widths=[1.7*cm, 9.5*cm, 1.4*cm, 2.3*cm, 2.2*cm, 2.1*cm], align_center_cols=[0,2,3,4,5]))

    story.append(Spacer(1, 0.15*cm))
    story.append(Paragraph("Itens com desvio ou atenção", stl["h"]))
    desvios = df_itens[(df_itens["Aplicável"] == "Não") | (df_itens["Status"].isin(["Parcialmente Conforme", "Não Conforme"])) | (df_itens["PAC"] == "Sim")].copy()
    if desvios.empty:
        story.append(Paragraph("Não foram registrados desvios, itens não aplicáveis ou PACs no checklist selecionado.", stl["body"]))
    else:
        desvios_pdf = desvios[["Nº", "Tag", "Pergunta", "Status", "PAC", "Comentário"]].copy().head(35)
        story.append(relatorios_pdf_tabela([list(desvios_pdf.columns)] + desvios_pdf.astype(str).values.tolist(), col_widths=[1.0*cm, 1.5*cm, 11.5*cm, 2.5*cm, 1.1*cm, 6.0*cm], header_bg="#334155", align_center_cols=[0,1,3,4]))
        if len(desvios) > 35:
            story.append(Paragraph(f"Exibidos 35 de {len(desvios)} itens com desvio/atenção. A lista completa está disponível no Excel do pacote de auditoria.", stl["small"]))

    story.append(Spacer(1, 0.15*cm))
    story.append(Paragraph("Checklist completo", stl["h"]))
    completo_pdf = df_itens[["Nº", "Tag", "Pergunta", "Modalidade", "Status", "Maturidade", "PAC"]].copy()
    completo_pdf["Maturidade"] = completo_pdf["Maturidade"].apply(lambda x: relatorios_fmt_num(x, 1))
    story.append(relatorios_pdf_tabela([list(completo_pdf.columns)] + completo_pdf.astype(str).values.tolist(), col_widths=[0.9*cm, 1.4*cm, 13.8*cm, 2.0*cm, 2.4*cm, 1.6*cm, 1.0*cm], header_bg="#0f172a", align_center_cols=[0,1,3,4,5,6]))

    if df_pacs is not None and not df_pacs.empty:
        story.append(Spacer(1, 0.15*cm))
        story.append(Paragraph("PACs vinculados", stl["h"]))
        pac_cols = [c for c in ["ID", "Site", "Tipo de achado", "Prioridade", "Status", "Prazo", "Responsável", "Descrição"] if c in df_pacs.columns]
        pac_pdf = df_pacs[pac_cols].copy().head(20)
        story.append(relatorios_pdf_tabela([list(pac_pdf.columns)] + pac_pdf.astype(str).values.tolist(), col_widths=[1.1*cm, 1.4*cm, 3.2*cm, 2.0*cm, 2.0*cm, 1.8*cm, 3.0*cm, 9.0*cm][:len(pac_cols)], header_bg="#334155"))

    story.append(Spacer(1, 0.12*cm))
    story.append(Paragraph("Observação: este relatório usa o checklist ativo de Auditoria Cruzada, composto por 80 perguntas corridas com tags por Diretriz EHS 4.12 e temas dos procedimentos de alto risco integrados às diretrizes correspondentes.", stl["small"]))
    doc.build(story)
    return buf.getvalue()


def ehs_relatorios(db,u):
    header("Relatórios Auditoria Cruzada","Exportações em Excel e PDF alinhadas ao checklist corrido atual de Diretrizes EHS")
    ids = visible_site_ids(u, db)
    da = df_aud(db, ids)
    dp = df_pac_ehs(db, ids)
    base = ehs_checklist_base_df(db)
    if not base.empty:
        st.caption(f"Checklist ativo usado nos relatórios: {len(base)} perguntas corridas, com tags por diretriz e modalidade sugerida de verificação.")
    download_excel_button("Checklist atual Excel", "checklist_ehs_atual.xlsx", {"Checklist_Atual": base})
    download_excel_button("PAC EHS Excel", "pac_ehs.xlsx", {"PAC": dp})
    download_excel_button("Pacote Auditoria Excel", "auditoria_cruzada_ehs.xlsx", {"Auditorias": da, "Checklist_Atual": base, "PAC": dp})

    auds = db.query(AuditoriaCruzada).filter(AuditoriaCruzada.site_auditado_id.in_(ids)).order_by(AuditoriaCruzada.id.desc()).all()
    if not auds:
        empty_state("Nenhuma auditoria disponível para emissão de relatório.")
        return

    amap = {f"{a.id} — {site_code(db,a.site_auditado_id)} — {a.ciclo} — {a.status}": a.id for a in auds}
    a = db.get(AuditoriaCruzada, amap[st.selectbox("Relatório PDF", list(amap))])
    gerar_checklist_automatico_ehs(db, a.id)
    df_itens = ehs_respostas_auditoria_df(db, a)
    df_resumo = ehs_resumo_diretriz_df(df_itens)
    pacs_aud = dp[dp["Auditoria"] == a.id] if not dp.empty and "Auditoria" in dp.columns else pd.DataFrame()

    c1, c2, c3, c4 = st.columns(4)
    res_obj = db.query(RespostaAuditoriaEHS).filter_by(auditoria_id=a.id).all()
    c1.metric("Conformidade", f"{calcular_conformidade_ehs(res_obj)}%")
    c2.metric("Maturidade", calcular_maturidade_ehs(res_obj))
    c3.metric("Itens do checklist", len(df_itens))
    c4.metric("PACs vinculados", len(pacs_aud) if pacs_aud is not None else 0)

    with st.expander("Prévia do resultado por diretriz", expanded=False):
        if df_resumo.empty:
            empty_state("Sem resumo disponível.")
        else:
            st.dataframe(df_resumo, use_container_width=True, hide_index=True)

    with st.expander("Prévia do checklist completo da auditoria", expanded=False):
        if df_itens.empty:
            empty_state("Checklist sem itens.")
        else:
            st.dataframe(df_itens, use_container_width=True, hide_index=True)

    pdf = gerar_pdf_auditoria_ehs(a, df_itens, pacs_aud, u.nome if u else "—")
    download_pdf_button("Baixar relatório de auditoria PDF", f"relatorio_auditoria_ehs_{a.id}.pdf", pdf, key=f"pdf_auditoria_ehs_{a.id}")

def procedimentos_ar_limpa_texto(v, limite=None):
    if v is None or (isinstance(v, float) and pd.isna(v)):
        return ""
    txt = re.sub(r"\s+", " ", str(v)).strip()
    if limite and len(txt) > limite:
        return txt[:limite-1].rstrip() + "…"
    return txt

def procedimentos_ar_ascii(v):
    return unicodedata.normalize("NFKD", procedimentos_ar_limpa_texto(v)).encode("ascii", "ignore").decode("ascii").lower()

def procedimentos_ar_status(v):
    n = procedimentos_ar_ascii(v)
    if not n:
        return "Não avaliado"
    if "parcial" in n:
        return "Conformidade Parcial"
    if "nao" in n or "não" in str(v).lower():
        return "Não Conforme"
    if "conforme" in n:
        return "Conforme"
    return procedimentos_ar_limpa_texto(v, 80) or "Não avaliado"

def procedimentos_ar_atendido_status(v):
    return procedimentos_ar_status(v) == "Conforme"

def procedimentos_ar_seed_df():
    try:
        raw = zlib.decompress(base64.b64decode(PROCEDIMENTOS_AR_SEED_B64)).decode("utf-8")
        return pd.read_csv(io.StringIO(raw))
    except Exception:
        logging.exception("Falha ao carregar seed de procedimentos de alto risco")
        return pd.DataFrame()


DIRETRIZ_EHS_LABELS = {
    "4.12.01": "Diretriz EHS 4.12.01 — Requisitos e Responsabilidades de EHS",
    "4.12.02": "Diretriz EHS 4.12.02 — Sistema de Gestão Ambiental",
    "4.12.03": "Diretriz EHS 4.12.03 — Métricas de Desempenho e Revisão do Progresso",
    "4.12.04": "Diretriz EHS 4.12.04 — Avaliação e Ação Corretiva",
    "4.12.05": "Diretriz EHS 4.12.05 — Gestão de Mudanças",
    "4.12.06": "Diretriz EHS 4.12.06 — Near Miss e Investigação de Acidentes/Incidentes",
    "4.12.07": "Diretriz EHS 4.12.07 — Uso de Produtos Químicos e Gestão de Resíduos",
    "4.12.08": "Diretriz EHS 4.12.08 — Segurança Elétrica",
    "4.12.09": "Diretriz EHS 4.12.09 — Preparação para Emergências",
    "4.12.10": "Diretriz EHS 4.12.10 — Treinamento e Envolvimento dos Empregados",
    "4.12.11": "Diretriz EHS 4.12.11 — Segurança de Equipamentos e Máquinas",
    "4.12.12": "Diretriz EHS 4.12.12 — Ergonomia",
    "4.12.13": "Diretriz EHS 4.12.13 — Permissões para Trabalho Perigoso",
    "4.12.14": "Diretriz EHS 4.12.14 — JSA e Equipamento de Proteção Individual",
    "4.12.15": "Diretriz EHS 4.12.15 — Movimentação e Armazenamento de Materiais",
    "4.12.16": "Diretriz EHS 4.12.16 — Visitantes, Contratados e Empregados Temporários",
    "4.12.17": "Diretriz EHS 4.12.17 — Ambiente de Trabalho",
    "4.12.18": "Diretriz EHS 4.12.18 — Segurança em Manutenção",
}

def _ehs_norm_question(txt):
    txt = unicodedata.normalize("NFKD", str(txt or "")).encode("ascii", "ignore").decode("ascii").lower()
    txt = re.sub(r"[^a-z0-9]+", " ", txt).strip()
    return txt

def ehs_diretriz_para_procedimento(row):
    fonte = procedimentos_ar_limpa_texto(row.get("fonte", ""))
    padrao = procedimentos_ar_ascii(row.get("padrao", ""))
    codigos = re.findall(r"4\.12\.\d{2}", fonte)
    if codigos:
        for c in codigos:
            if c in DIRETRIZ_EHS_LABELS:
                return DIRETRIZ_EHS_LABELS[c]
    inferencias = [
        (("quim" in padrao or "resid" in padrao), "4.12.07"),
        (("eletric" in padrao), "4.12.08"),
        (("loto" in padrao or "energia" in padrao or "maquina" in padrao), "4.12.11"),
        (("queda" in padrao or "caminhada" in padrao or "superficie" in padrao), "4.12.17"),
        (("veicul" in padrao or "industriais" in padrao or "movimenta" in padrao), "4.12.15"),
        (("licenc" in padrao or "ambient" in padrao), "4.12.01"),
    ]
    for cond, codigo in inferencias:
        if cond:
            return DIRETRIZ_EHS_LABELS[codigo]
    return DIRETRIZ_EHS_LABELS["4.12.04"]

def checklist_ehs_unificado():
    """Checklist único e enxuto das Diretrizes EHS 4.12.

    Os requisitos do High Risk Framework foram incorporados como perguntas essenciais
    dentro das diretrizes correspondentes, evitando um checklist excessivamente longo.
    """
    checklist = {cat: list(pergs) for cat, pergs in CHECKLIST_EHS_DIRETRIZES_BASE.items()}
    saida = {}
    for cat, pergs in checklist.items():
        vistos = set()
        limpas = []
        for pergunta in pergs:
            pergunta = str(pergunta or "").strip()
            if not pergunta:
                continue
            chave = _ehs_norm_question(pergunta)
            if chave in vistos:
                continue
            limpas.append(pergunta)
            vistos.add(chave)
        saida[cat] = limpas
    return saida

CHECKLIST_EHS = checklist_ehs_unificado()

def procedimentos_ar_mapping_from_row(r):
    return {
        "padrao": procedimentos_ar_limpa_texto(r.get("padrao"), 240),
        "aba_origem": procedimentos_ar_limpa_texto(r.get("aba_origem"), 120),
        "elemento": procedimentos_ar_limpa_texto(r.get("elemento"), 40),
        "etapa": procedimentos_ar_limpa_texto(r.get("etapa"), 40),
        "expectativa": procedimentos_ar_limpa_texto(r.get("expectativa")),
        "fonte": procedimentos_ar_limpa_texto(r.get("fonte"), 260),
        "regulamentacao": procedimentos_ar_limpa_texto(r.get("regulamentacao"), 260),
        "periodicidade": procedimentos_ar_limpa_texto(r.get("periodicidade"), 160),
        "pergunta": procedimentos_ar_limpa_texto(r.get("pergunta")),
        "resposta": procedimentos_ar_limpa_texto(r.get("resposta")),
        "desempenho": procedimentos_ar_status(r.get("desempenho")),
        "origem_arquivo": procedimentos_ar_limpa_texto(r.get("origem_arquivo"), 260),
    }

def seed_procedimentos_alto_risco_inicial(db):
    try:
        if db.query(ProcedimentoAltoRiscoRegistro).count() > 0:
            return
        df = procedimentos_ar_seed_df()
        if df.empty:
            return
        regs = [procedimentos_ar_mapping_from_row(row.to_dict()) for _, row in df.iterrows()]
        db.bulk_insert_mappings(ProcedimentoAltoRiscoRegistro, regs)
        db.add(ProcedimentoAltoRiscoUploadHistorico(nome_arquivo="High_Risk_Framework_2019_PT_BR.xlsx", linhas_importadas=len(regs), usuario="Sistema", observacoes="Carga inicial embutida"))
        db.flush()
    except Exception:
        logging.exception("Falha ao popular procedimentos de alto risco")

def parse_procedimentos_alto_risco_excel(file_obj, origem_nome="upload.xlsx"):
    try:
        data = file_obj.getvalue() if hasattr(file_obj, "getvalue") else file_obj
        xl = pd.ExcelFile(io.BytesIO(data) if isinstance(data, (bytes, bytearray)) else data)
    except Exception as e:
        raise ValueError(f"Não foi possível abrir o arquivo de procedimentos: {e}")
    rows = []
    abas_ignoradas = {"instrucoes", "instruções", "pontuacao", "pontuação", "formulas", "fórmulas"}
    for sh in xl.sheet_names:
        if procedimentos_ar_ascii(sh) in abas_ignoradas:
            continue
        df = pd.read_excel(xl, sheet_name=sh, header=None)
        if df.empty or df.shape[1] < 6:
            continue
        titulo = procedimentos_ar_limpa_texto(df.iloc[0,1] if df.shape[1] > 1 and pd.notna(df.iloc[0,1]) else sh, 240)
        titulo = re.sub(r"^Padrão de Alto Risco:\s*", "", titulo).strip()
        for _, row in df.iterrows():
            elem = row.iloc[0] if df.shape[1] > 0 else None
            exp = row.iloc[1] if df.shape[1] > 1 else None
            if pd.isna(elem) or pd.isna(exp):
                continue
            elem = procedimentos_ar_limpa_texto(elem, 40)
            if not re.match(r"^\d+(\.\d+)+$", elem):
                continue
            rows.append({
                "padrao": titulo or sh,
                "aba_origem": sh,
                "elemento": elem,
                "etapa": elem.split(".")[0],
                "expectativa": procedimentos_ar_limpa_texto(exp),
                "fonte": procedimentos_ar_limpa_texto(row.iloc[2] if df.shape[1] > 2 else "", 260),
                "regulamentacao": procedimentos_ar_limpa_texto(row.iloc[3] if df.shape[1] > 3 else "", 260),
                "periodicidade": procedimentos_ar_limpa_texto(row.iloc[4] if df.shape[1] > 4 else "", 160),
                "pergunta": procedimentos_ar_limpa_texto(row.iloc[5] if df.shape[1] > 5 else ""),
                "resposta": procedimentos_ar_limpa_texto(row.iloc[6] if df.shape[1] > 6 else ""),
                "desempenho": procedimentos_ar_status(row.iloc[7] if df.shape[1] > 7 else ""),
                "origem_arquivo": origem_nome,
            })
    return rows

def procedimentos_ar_df(db):
    rows = []
    for r in db.query(ProcedimentoAltoRiscoRegistro).order_by(ProcedimentoAltoRiscoRegistro.padrao, ProcedimentoAltoRiscoRegistro.elemento).all():
        rows.append({
            "ID": r.id,
            "Padrão / Procedimento": r.padrao or "—",
            "Aba origem": r.aba_origem or "—",
            "Elemento": r.elemento or "—",
            "Etapa": r.etapa or "—",
            "Expectativa de desempenho": r.expectativa or "—",
            "Fonte / Diretriz": r.fonte or "—",
            "Regulamentação": r.regulamentacao or "—",
            "Periodicidade": r.periodicidade or "—",
            "Pergunta de auditoria": r.pergunta or "—",
            "Resposta / Evidência": r.resposta or "—",
            "Desempenho": procedimentos_ar_status(r.desempenho),
            "Origem arquivo": r.origem_arquivo or "—",
        })
    df = pd.DataFrame(rows)
    if not df.empty:
        df["Atendido"] = df["Desempenho"].apply(procedimentos_ar_atendido_status)
    return df

def procedimentos_ar_filtrar_df(df, padroes=None, etapas=None, desempenho=None, fontes=None, periodicidades=None):
    f = df.copy()
    if padroes: f = f[f["Padrão / Procedimento"].isin(padroes)]
    if etapas: f = f[f["Etapa"].astype(str).isin([str(x) for x in etapas])]
    if desempenho: f = f[f["Desempenho"].isin(desempenho)]
    if fontes: f = f[f["Fonte / Diretriz"].isin(fontes)]
    if periodicidades: f = f[f["Periodicidade"].isin(periodicidades)]
    return f

def procedimentos_ar_kpis(df):
    total = len(df) if df is not None else 0
    conf = int((df["Desempenho"] == "Conforme").sum()) if total and "Desempenho" in df.columns else 0
    parcial = int((df["Desempenho"] == "Conformidade Parcial").sum()) if total and "Desempenho" in df.columns else 0
    nc = int((df["Desempenho"] == "Não Conforme").sum()) if total and "Desempenho" in df.columns else 0
    taxa = round(conf / total * 100, 1) if total else 0
    return total, conf, parcial, nc, taxa

def procedimentos_ar_submodulo_home_card(db):
    df = procedimentos_ar_df(db)
    total, conf, parcial, nc, taxa = procedimentos_ar_kpis(df)
    return [
        ("Procedimentos • Itens", total, "Padrões de alto risco"),
        ("Procedimentos • Conformidade", f"{taxa}%", "Itens conformes / total"),
        ("Procedimentos • Parciais", parcial, "Itens em conformidade parcial"),
        ("Procedimentos • Não conformes", nc, "Itens com lacuna"),
    ]

def procedimentos_ar_dashboard(db,u):
    header("Dashboard Procedimentos de Alto Risco", "Visão dos padrões/procedimentos do High Risk Framework, segmentados por padrão, etapa, fonte e desempenho")
    df = procedimentos_ar_df(db)
    if df.empty:
        empty_state("Nenhum procedimento de alto risco carregado.")
        return
    mostrar_ultima_atualizacao_modulo(db, "ehs", u)
    with st.expander("Filtros", expanded=True):
        c1,c2,c3,c4 = st.columns(4)
        padroes = c1.multiselect("Padrão / Procedimento", sorted(df["Padrão / Procedimento"].dropna().unique()))
        etapas = c2.multiselect("Etapa", sorted(df["Etapa"].dropna().astype(str).unique()))
        desempenho = c3.multiselect("Desempenho", [s for s in PROCEDIMENTOS_AR_STATUS_ORDER if s in set(df["Desempenho"])])
        fontes_opts = sorted([x for x in df["Fonte / Diretriz"].dropna().unique() if x and x != "—"])
        fontes = c4.multiselect("Fonte / Diretriz", fontes_opts[:80])
        periodicidades = st.multiselect("Periodicidade", sorted([x for x in df["Periodicidade"].dropna().unique() if x and x != "—"]))
    f = procedimentos_ar_filtrar_df(df, padroes, etapas, desempenho, fontes, periodicidades)
    total, conf, parcial, nc, taxa = procedimentos_ar_kpis(f)
    c1,c2,c3,c4 = st.columns(4)
    c1.metric("Itens avaliados", total)
    c2.metric("Conformidade", f"{taxa}%")
    c3.metric("Parciais", parcial)
    c4.metric("Não conformes", nc)
    tabs = st.tabs(["Resumo", "Padrões", "Lacunas", "Base"])
    with tabs[0]:
        a1,a2 = st.columns(2)
        with a1:
            status_df = f.groupby("Desempenho", as_index=False).size().rename(columns={"size":"Quantidade"}) if not f.empty else pd.DataFrame()
            if not status_df.empty:
                fig = px.bar(status_df, x="Desempenho", y="Quantidade", color="Desempenho", text="Quantidade", title="Distribuição por desempenho", category_orders={"Desempenho": PROCEDIMENTOS_AR_STATUS_ORDER}, color_discrete_map=PROCEDIMENTOS_AR_STATUS_COLOR_MAP)
                fig.update_layout(template="plotly_white", showlegend=False)
                fig.update_traces(textposition="outside", textfont_color="#111827")
                plotly_chart_safe(fig, use_container_width=True)
            else:
                empty_state("Sem dados para os filtros.")
        with a2:
            pad_df = f.groupby("Padrão / Procedimento", as_index=False).agg(Total=("ID","count"), Conformes=("Atendido","sum")) if not f.empty else pd.DataFrame()
            if not pad_df.empty:
                pad_df["Conformidade %"] = (pad_df["Conformes"] / pad_df["Total"] * 100).round(1)
                fig = px.bar(pad_df.sort_values("Conformidade %"), x="Conformidade %", y="Padrão / Procedimento", orientation="h", text="Conformidade %", color="Conformidade %", title="Conformidade por padrão/procedimento", color_continuous_scale=["#dc2626", "#f59e0b", "#16a34a"])
                fig.update_layout(template="plotly_white", coloraxis_showscale=False, xaxis_range=[0,100])
                fig.update_traces(texttemplate="%{text:.1f}%", textposition="outside", textfont_color="#111827")
                plotly_chart_safe(fig, use_container_width=True)
            else:
                empty_state("Sem dados por procedimento.")
    with tabs[1]:
        pad_status = f.groupby(["Padrão / Procedimento","Desempenho"], as_index=False).size().rename(columns={"size":"Quantidade"}) if not f.empty else pd.DataFrame()
        if not pad_status.empty:
            fig = px.bar(pad_status, x="Padrão / Procedimento", y="Quantidade", color="Desempenho", barmode="stack", text="Quantidade", title="Itens por padrão e desempenho", category_orders={"Desempenho": PROCEDIMENTOS_AR_STATUS_ORDER}, color_discrete_map=PROCEDIMENTOS_AR_STATUS_COLOR_MAP)
            fig.update_layout(template="plotly_white", xaxis_tickangle=-25)
            fig.update_traces(textfont_color="#111827")
            plotly_chart_safe(fig, use_container_width=True)
        st.dataframe(pad_status, use_container_width=True, hide_index=True)
    with tabs[2]:
        lac = f[f["Desempenho"].isin(["Não Conforme", "Conformidade Parcial", "Não avaliado"])].copy()
        if lac.empty:
            st.success("Nenhuma lacuna encontrada nos filtros selecionados.")
        else:
            top = lac.groupby("Padrão / Procedimento", as_index=False).size().rename(columns={"size":"Lacunas"}).sort_values("Lacunas", ascending=False)
            fig = px.bar(top, x="Lacunas", y="Padrão / Procedimento", orientation="h", text="Lacunas", color="Lacunas", title="Padrões com mais lacunas", color_continuous_scale=["#fef3c7", "#f59e0b", "#dc2626"])
            fig.update_layout(template="plotly_white", coloraxis_showscale=False)
            fig.update_traces(textposition="outside", textfont_color="#111827")
            plotly_chart_safe(fig, use_container_width=True)
            cols = ["Padrão / Procedimento","Elemento","Etapa","Desempenho","Pergunta de auditoria","Resposta / Evidência","Fonte / Diretriz","Periodicidade"]
            st.dataframe(lac[cols], use_container_width=True, hide_index=True)
    with tabs[3]:
        cols = ["Padrão / Procedimento","Elemento","Etapa","Desempenho","Expectativa de desempenho","Pergunta de auditoria","Resposta / Evidência","Fonte / Diretriz","Periodicidade"]
        st.dataframe(f[cols], use_container_width=True, hide_index=True)
        download_excel_button("Exportar procedimentos filtrados", "procedimentos_alto_risco.xlsx", {"Procedimentos": f[cols]}, key="download_proc_ar_dashboard")

def procedimentos_ar_base_page(db,u):
    header("Base Procedimentos de Alto Risco", "Consulta consolidada do High Risk Framework")
    df = procedimentos_ar_df(db)
    if df.empty:
        empty_state("Nenhuma base carregada.")
        return
    c1,c2,c3 = st.columns(3)
    c1.metric("Itens", len(df))
    c2.metric("Padrões", df["Padrão / Procedimento"].nunique())
    c3.metric("Última atualização", ultima_atualizacao_modulo(db, "ehs"))
    st.dataframe(df, use_container_width=True, hide_index=True)
    download_excel_button("Exportar base de procedimentos", "base_procedimentos_alto_risco.xlsx", {"Base": df}, key="download_base_proc_ar")

def procedimentos_ar_atualizar_base(db,u):
    header("Atualizar Procedimentos de Alto Risco", "Importe a planilha High Risk Framework para substituir a base de procedimentos")
    if not can_update_bases(u):
        alert_card("Atualização restrita ao administrador principal.")
        return
    st.caption(f"Última atualização registrada: {ultima_atualizacao_modulo(db, 'ehs')}")
    up = st.file_uploader("Selecionar planilha High Risk Framework", type=["xlsx", "xls"], key="upload_proc_alto_risco")
    if up:
        try:
            regs = parse_procedimentos_alto_risco_excel(up, up.name)
            st.success(f"Arquivo lido com {len(regs)} itens de procedimento.")
            amostra = pd.DataFrame(regs).head(30)
            st.dataframe(amostra, use_container_width=True, hide_index=True)
            if st.button("Substituir base de procedimentos", use_container_width=True, type="primary", key="btn_substituir_proc_ar"):
                db.query(ProcedimentoAltoRiscoRegistro).delete()
                db.flush()
                if regs:
                    db.bulk_insert_mappings(ProcedimentoAltoRiscoRegistro, regs)
                db.add(ProcedimentoAltoRiscoUploadHistorico(nome_arquivo=up.name, linhas_importadas=len(regs), usuario=u.nome if u else "—", observacoes="Substituição manual da base de procedimentos"))
                registrar_versao_base(db, "ehs", "Procedimentos de Alto Risco", up.name, len(regs), u, "Substituição manual da base de procedimentos")
                db.commit()
                st.cache_data.clear()
                st.success("Base de procedimentos atualizada.")
                st.rerun()
        except Exception as e:
            st.error(f"Falha ao processar arquivo: {e}")


