LEGAL_SEED_B64 = """"""

def legal_limpa_texto(v, limite=None):
    if v is None:
        return ""
    try:
        if pd.isna(v):
            return ""
    except Exception:
        pass
    s = str(v).replace("\r", " ").replace("\n", " ").strip()
    s = re.sub(r"\s+", " ", s)
    if limite and len(s) > limite:
        return s[:limite].rstrip()
    return s

def legal_ascii(v):
    return unicodedata.normalize("NFKD", str(v or "")).encode("ascii", "ignore").decode("ascii").lower().strip()

def legal_status_legislacao(v):
    n = legal_ascii(v)
    if not n or n == "nan":
        return "Não verificado"
    if "nao atend" in n or "nao conforme" in n:
        return "Não atendido"
    if "atendid" in n or n == "conforme":
        return "Atendido"
    if "analise" in n:
        return "Em análise"
    if "adequacao" in n:
        return "Em Adequação"
    if "nao verific" in n or "nao aval" in n:
        return "Não verificado"
    return legal_limpa_texto(v, 80)

def legal_status_obrigacao(v):
    n = legal_ascii(v)
    if not n or n == "nan":
        return "Não verificada"
    if "nao atend" in n or "nao conforme" in n:
        return "Não atendida"
    if "atendid" in n or n == "conforme":
        return "Atendida"
    if "analise" in n:
        return "Em análise"
    if "nao verific" in n or "nao aval" in n:
        return "Não verificada"
    return legal_limpa_texto(v, 80)

def legal_atendido_status(v):
    n = legal_ascii(v)
    return ("atendid" in n or n == "conforme") and "nao" not in n

def legal_site_from_unidade(v):
    n = legal_ascii(v)
    if "cachoeirinha" in n:
        return "CAC"
    if "jacarei" in n:
        return "JAC"
    if "sao jose" in n:
        return "SJC"
    if "diadema" in n:
        return "DIA"
    if "sao paulo" in n or "perus" in n:
        return "PER"
    if "jundiai" in n:
        return "JUN"
    return normalize_site_code(v)

def legal_norm_date(v):
    if v in (None, ""):
        return None
    if isinstance(v, datetime):
        return v.date()
    if isinstance(v, date):
        return v
    try:
        d = pd.to_datetime(v, dayfirst=True, errors="coerce")
        return d.date() if pd.notna(d) else None
    except Exception:
        return None

def legal_seed_df():
    try:
        raw = zlib.decompress(base64.b64decode(LEGAL_SEED_B64.encode("ascii")))
        return pd.read_csv(io.StringIO(raw.decode("utf-8")), dtype=str).fillna("")
    except Exception:
        logging.exception("Falha ao carregar base inicial legal")
        return pd.DataFrame()

def legal_mapping_from_row(r):
    site = legal_site_from_unidade(r.get("site_codigo") or r.get("Unidade") or r.get("unidade_original"))
    if site not in SITES_LAG or site == "Corporativo":
        site = "JUN" if str(r.get("origem_base", "")).lower().startswith("lira") else site
    info = SITES_LAG.get(site, {})
    origem_base_norm = legal_limpa_texto(r.get("origem_base"), 120)
    if origem_base_norm and "lira" not in legal_ascii(origem_base_norm):
        origem_base_norm = "LEMA"
    return {
        "origem_base": origem_base_norm,
        "site_codigo": site,
        "site_nome": info.get("nome", legal_limpa_texto(r.get("site_nome") or r.get("unidade_original"), 160)),
        "grupo": info.get("grupo", legal_limpa_texto(r.get("grupo"), 80)),
        "divisao": info.get("divisao", legal_limpa_texto(r.get("divisao"), 160)),
        "legislacao_id": legal_limpa_texto(r.get("legislacao_id"), 320),
        "codigo": legal_limpa_texto(r.get("codigo"), 120),
        "legislacao": legal_limpa_texto(r.get("legislacao"), 600),
        "descricao_legislacao": legal_limpa_texto(r.get("descricao_legislacao"), 900),
        "assunto": legal_limpa_texto(r.get("assunto"), 260),
        "macrotema": legal_limpa_texto(r.get("macrotema"), 260),
        "ambito": legal_limpa_texto(r.get("ambito"), 120),
        "origem_norma": legal_limpa_texto(r.get("origem_norma"), 160),
        "aplicabilidade": legal_limpa_texto(r.get("aplicabilidade"), 120),
        "prioridade_legislacao": legal_limpa_texto(r.get("prioridade_legislacao"), 80),
        "responsavel_legislacao": legal_limpa_texto(r.get("responsavel_legislacao"), 260),
        "status_legislacao": legal_status_legislacao(r.get("status_legislacao")),
        "obrigacao_id": legal_limpa_texto(r.get("obrigacao_id"), 360),
        "obrigacao": legal_limpa_texto(r.get("obrigacao"), 1000),
        "prioridade_obrigacao": legal_limpa_texto(r.get("prioridade_obrigacao"), 80),
        "responsavel_obrigacao": legal_limpa_texto(r.get("responsavel_obrigacao"), 260),
        "status_obrigacao": legal_status_obrigacao(r.get("status_obrigacao")),
        "data_referencia": legal_norm_date(r.get("data_referencia")),
        "data_preenchimento": legal_norm_date(r.get("data_preenchimento")),
        "origem_arquivo": legal_limpa_texto(r.get("origem_arquivo"), 260),
    }

def seed_legal_inicial(db):
    try:
        if db.query(LegalRegistro).count() > 0:
            return
        df = legal_seed_df()
        if df.empty:
            return
        regs = [legal_mapping_from_row(r.to_dict()) for _, r in df.iterrows()]
        regs = [r for r in regs if r.get("site_codigo") and r.get("obrigacao_id")]
        if regs:
            db.bulk_insert_mappings(LegalRegistro, regs)
            db.add(LegalUploadHistorico(nome_arquivo="Base inicial", tipo_base="LIRA + Consolidado", linhas_importadas=len(regs), usuario="Sistema", observacoes="Carga inicial embutida no código"))
            db.commit()
    except Exception:
        db.rollback()
        logging.exception("Falha ao inserir base inicial legal")

def parse_legal_consolidado_5_sites(df, origem_nome):
    registros = []
    for idx, r in df.iterrows():
        site = legal_site_from_unidade(r.get("Unidade"))
        info = SITES_LAG.get(site, {})
        leg_doc = " ".join([legal_limpa_texto(r.get("Documento")), legal_limpa_texto(r.get("Origem")), legal_limpa_texto(r.get("Numero"))]).strip()
        desc_req = legal_limpa_texto(r.get("Ementa"), 900) or legal_limpa_texto(r.get("Assunto"), 260)
        leg_key = f"{site}|{legal_limpa_texto(r.get('Documento'))}|{legal_limpa_texto(r.get('Origem'))}|{legal_limpa_texto(r.get('Numero'))}|{legal_limpa_texto(r.get('Data'))}|{legal_limpa_texto(r.get('Ementa'), 90)}"
        registros.append({
            "origem_base": "LEMA",
            "site_codigo": site,
            "site_nome": info.get("nome", legal_limpa_texto(r.get("Unidade"), 160)),
            "grupo": info.get("grupo", ""),
            "divisao": info.get("divisao", ""),
            "legislacao_id": leg_key,
            "codigo": legal_limpa_texto(r.get("seq"), 120),
            "legislacao": legal_limpa_texto(leg_doc, 600),
            "descricao_legislacao": desc_req,
            "assunto": legal_limpa_texto(r.get("Assunto"), 260),
            "macrotema": legal_limpa_texto(r.get("Assunto"), 260),
            "ambito": legal_limpa_texto(r.get("Ambito"), 120),
            "origem_norma": legal_limpa_texto(r.get("Origem"), 160),
            "aplicabilidade": "",
            "prioridade_legislacao": "",
            "responsavel_legislacao": "",
            "status_legislacao": legal_status_legislacao(r.get("Atendimento da Legislacao")),
            "obrigacao_id": f"{leg_key}|{idx}",
            "obrigacao": legal_limpa_texto(r.get("Acao"), 1000),
            "prioridade_obrigacao": "",
            "responsavel_obrigacao": legal_limpa_texto(r.get("Responsavel pela Acao"), 260),
            "status_obrigacao": legal_status_obrigacao(r.get("Atendimento da Acao")),
            "data_referencia": legal_norm_date(r.get("Data")),
            "data_preenchimento": legal_norm_date(r.get("Data do Preenchimento")),
            "origem_arquivo": origem_nome,
        })
    return pd.DataFrame(registros)

def parse_legal_lira_jundiai(df, origem_nome):
    registros = []
    site = "JUN"; info = SITES_LAG[site]
    for idx, r in df.iterrows():
        codigo = legal_limpa_texto(r.get("Código"), 120)
        desc = legal_limpa_texto(r.get("Descrição do Requisito"), 600)
        leg_key = f"{site}|{codigo}|{desc[:110]}"
        registros.append({
            "origem_base": "LIRA Jundiaí",
            "site_codigo": site,
            "site_nome": info["nome"],
            "grupo": info["grupo"],
            "divisao": info["divisao"],
            "legislacao_id": leg_key,
            "codigo": codigo,
            "legislacao": desc,
            "descricao_legislacao": legal_limpa_texto(r.get("Sumário"), 900),
            "assunto": legal_limpa_texto(r.get("Temas"), 260),
            "macrotema": legal_limpa_texto(r.get("Macrotemas"), 260),
            "ambito": legal_limpa_texto(r.get("Origem"), 120),
            "origem_norma": legal_limpa_texto(r.get("Origem"), 160),
            "aplicabilidade": legal_limpa_texto(r.get("Aplicabilidade"), 120),
            "prioridade_legislacao": legal_limpa_texto(r.get("Prioridade do requisito"), 80),
            "responsavel_legislacao": legal_limpa_texto(r.get("Responsável do requisito"), 260),
            "status_legislacao": legal_status_legislacao(r.get("Situação do requisito")),
            "obrigacao_id": f"{leg_key}|{idx}",
            "obrigacao": legal_limpa_texto(r.get("Descrição da Obrigação"), 1000),
            "prioridade_obrigacao": legal_limpa_texto(r.get("Prioridade da obrigação"), 80),
            "responsavel_obrigacao": legal_limpa_texto(r.get("Responsável Obrigação"), 260),
            "status_obrigacao": legal_status_obrigacao(r.get("Conformidade da obrigação")),
            "data_referencia": legal_norm_date(r.get("Data de publicação")),
            "data_preenchimento": legal_norm_date(r.get("Data de atualização da evidência")),
            "origem_arquivo": origem_nome,
        })
    return pd.DataFrame(registros)

def parse_legal_excel(file_obj, origem_nome="upload.xlsx"):
    try:
        xls = pd.ExcelFile(file_obj)
    except Exception as e:
        raise ValueError(f"Não foi possível ler o arquivo {origem_nome}: {e}")
    frames = []
    for sheet in xls.sheet_names:
        df = pd.read_excel(xls, sheet_name=sheet)
        cols = set(df.columns.astype(str))
        if {"Unidade", "Atendimento da Legislacao", "Atendimento da Acao", "Acao"}.issubset(cols):
            frames.append(parse_legal_consolidado_5_sites(df, origem_nome))
        elif {"Situação do requisito", "Código", "Descrição do Requisito", "Conformidade da obrigação", "Descrição da Obrigação"}.issubset(cols):
            frames.append(parse_legal_lira_jundiai(df, origem_nome))
    if not frames:
        return pd.DataFrame()
    out = pd.concat(frames, ignore_index=True)
    out = out.dropna(subset=["site_codigo"])
    return out

def legal_df(db):
    rows = []
    for r in db.query(LegalRegistro).order_by(LegalRegistro.site_codigo, LegalRegistro.origem_base, LegalRegistro.id).all():
        rows.append({
            "ID": r.id,
            "Origem base": r.origem_base or "—",
            "Site código": r.site_codigo or "—",
            "Site": site_nome_curto(r.site_codigo) if r.site_codigo else (r.site_nome or "—"),
            "Site nome": r.site_nome or "—",
            "Grupo": r.grupo or "—",
            "Divisão": r.divisao or "—",
            "Legislação ID": r.legislacao_id or "—",
            "Código": r.codigo or "—",
            "Legislação": r.legislacao or "—",
            "Descrição legislação": r.descricao_legislacao or "—",
            "Assunto": r.assunto or "—",
            "Macrotema": r.macrotema or "—",
            "Âmbito/Origem": r.ambito or r.origem_norma or "—",
            "Origem norma": r.origem_norma or "—",
            "Aplicabilidade": r.aplicabilidade or "—",
            "Prioridade legislação": r.prioridade_legislacao or "—",
            "Responsável legislação": r.responsavel_legislacao or "—",
            "Status legislação": r.status_legislacao or "Não verificado",
            "Obrigação ID": r.obrigacao_id or "—",
            "Obrigação": r.obrigacao or "—",
            "Prioridade obrigação": r.prioridade_obrigacao or "—",
            "Responsável obrigação": r.responsavel_obrigacao or "—",
            "Status obrigação": r.status_obrigacao or "Não verificada",
            "Data referência": r.data_referencia,
            "Data preenchimento": r.data_preenchimento,
            "Origem arquivo": r.origem_arquivo or "—",
        })
    df = pd.DataFrame(rows)
    if not df.empty:
        df["Legislação atendida"] = df["Status legislação"].apply(legal_atendido_status)
        df["Obrigação atendida"] = df["Status obrigação"].apply(legal_atendido_status)
    return df

def legal_filtrar_df(df, sites=None, divisoes=None, bases=None, assuntos=None, status_leg=None, status_obr=None, origem_norma=None, aplicabilidade=None):
    f = df.copy()
    if sites: f = f[f["Site código"].isin(sites)]
    if divisoes: f = f[f["Divisão"].isin(divisoes)]
    if bases: f = f[f["Origem base"].isin(bases)]
    if assuntos: f = f[f["Assunto"].isin(assuntos) | f["Macrotema"].isin(assuntos)]
    if status_leg: f = f[f["Status legislação"].isin(status_leg)]
    if status_obr: f = f[f["Status obrigação"].isin(status_obr)]
    if origem_norma: f = f[f["Origem norma"].isin(origem_norma) | f["Âmbito/Origem"].isin(origem_norma)]
    if aplicabilidade: f = f[f["Aplicabilidade"].isin(aplicabilidade)]
    return f

def legal_legislacoes_unicas(df):
    if df is None or df.empty:
        return pd.DataFrame()
    cols = ["Site código", "Site", "Divisão", "Origem base", "Legislação ID", "Legislação", "Status legislação", "Assunto", "Macrotema", "Âmbito/Origem", "Origem norma"]
    return df[cols].drop_duplicates(subset=["Site código", "Legislação ID"]).copy()

def legal_indicador_atendimento(df, tipo="legislacao"):
    if df is None or df.empty:
        return 0, 0, 0
    if tipo == "legislacao":
        base = legal_legislacoes_unicas(df)
        total = len(base)
        atendidas = int(base["Status legislação"].apply(legal_atendido_status).sum()) if total else 0
    else:
        total = len(df)
        atendidas = int(df["Status obrigação"].apply(legal_atendido_status).sum()) if total else 0
    taxa = round(atendidas / total * 100, 1) if total else 0
    return total, atendidas, taxa

def legal_taxa_por_site(df, tipo="legislacao"):
    if df is None or df.empty:
        return pd.DataFrame()
    rows = []
    for site, g in df.groupby("Site", dropna=False):
        total, atendidas, taxa = legal_indicador_atendimento(g, tipo)
        rows.append({"Site": site, "Atendidas": atendidas, "Total": total, "Taxa %": taxa})
    return pd.DataFrame(rows).sort_values("Taxa %", ascending=True)

def legal_taxa_por_divisao(df, tipo="legislacao"):
    if df is None or df.empty:
        return pd.DataFrame()
    rows = []
    for div, g in df.groupby("Divisão", dropna=False):
        total, atendidas, taxa = legal_indicador_atendimento(g, tipo)
        rows.append({"Divisão": div, "Atendidas": atendidas, "Total": total, "Taxa %": taxa})
    return pd.DataFrame(rows).sort_values("Taxa %", ascending=True)


def legal_fig_taxa(df_taxa, titulo, eixo="Site"):
    if df_taxa is None or df_taxa.empty:
        return None
    d = df_taxa.copy()
    d["Cor"] = d["Taxa %"].apply(lambda x: "#16a34a" if float(x or 0) >= LEGAL_META_ATENDIMENTO else "#facc15" if float(x or 0) >= 85 else "#dc2626")
    d["Meta"] = LEGAL_META_ATENDIMENTO
    fig = go.Figure()
    fig.add_trace(go.Bar(
        x=d["Taxa %"],
        y=d[eixo],
        orientation="h",
        text=d["Taxa %"].map(lambda x: f"{float(x or 0):.1f}%"),
        textposition="outside",
        marker=dict(color=d["Cor"], line=dict(color="#ffffff", width=1.2)),
        customdata=d[["Atendidas", "Total"]].values,
        hovertemplate="<b>%{y}</b><br>Atendimento: %{x:.1f}%<br>Atendidas: %{customdata[0]}<br>Total: %{customdata[1]}<extra></extra>",
        name="Atendimento",
    ))
    fig.add_vline(x=LEGAL_META_ATENDIMENTO, line_width=2, line_dash="dash", line_color="#15803d", annotation_text=f"Meta {LEGAL_META_ATENDIMENTO}%", annotation_position="top right")
    fig.update_yaxes(autorange="reversed", title=None, tickfont=dict(color="#111827"))
    fig.update_xaxes(title="Atendimento (%)", range=[0, 108], showgrid=True, gridcolor="rgba(148,163,184,0.22)", tickfont=dict(color="#111827"))
    fig.update_traces(textfont=dict(color="#111827", size=12))
    fig.update_layout(
        template="plotly_white",
        height=max(330, 48 * len(d) + 120),
        margin=dict(l=10, r=45, t=60, b=12),
        showlegend=False,
        title=dict(text=titulo, font=dict(color="#111827")),
        font=dict(color="#111827"),
        paper_bgcolor="#ffffff",
        plot_bgcolor="#ffffff",
    )
    return fig
def legal_top_lacunas(df, campo="Site", tipo="obrigacao", n=10):
    if df is None or df.empty:
        return pd.DataFrame()
    if tipo == "legislacao":
        base = legal_legislacoes_unicas(df)
        f = base[~base["Status legislação"].apply(legal_atendido_status)]
    else:
        f = df[~df["Status obrigação"].apply(legal_atendido_status)]
    if f.empty or campo not in f.columns:
        return pd.DataFrame()
    return f.groupby(campo, dropna=False).size().reset_index(name="Pendências").sort_values("Pendências", ascending=False).head(n)

def legal_cor_taxa(taxa):
    try:
        t = float(taxa or 0)
    except Exception:
        t = 0
    if t >= LEGAL_META_ATENDIMENTO:
        return "#16a34a"
    if t >= 85:
        return "#facc15"
    return "#dc2626"

def legal_status_site(taxa_obrigacao, pendencias):
    try:
        taxa = float(taxa_obrigacao or 0)
    except Exception:
        taxa = 0
    pend = int(pendencias or 0)
    if taxa >= LEGAL_META_ATENDIMENTO and pend == 0:
        return "Em conformidade"
    if taxa >= LEGAL_META_ATENDIMENTO:
        return "Bom acompanhamento"
    if taxa >= 85:
        return "Atenção"
    return "Prioritário"

def legal_resumo_sites(df):
    rows = []
    sites_base = [s for s in SITES_PADRAO if s in SITES_LAG]
    for cod in sites_base:
        site_df = df[df["Site código"] == cod].copy() if df is not None and not df.empty else pd.DataFrame()
        total_leg, atend_leg, taxa_leg = legal_indicador_atendimento(site_df, "legislacao")
        total_obr, atend_obr, taxa_obr = legal_indicador_atendimento(site_df, "obrigacao")
        pend_leg = max(total_leg - atend_leg, 0)
        pend_obr = max(total_obr - atend_obr, 0)
        rows.append({
            "Site": site_nome_curto(cod),
            "Código": cod,
            "Divisão": site_divisao(cod),
            "Legislações": int(total_leg),
            "Atend. legislação": f"{taxa_leg:.1f}%",
            "Pend. legislação": int(pend_leg),
            "Obrigações": int(total_obr),
            "Atend. obrigações": f"{taxa_obr:.1f}%",
            "Pend. obrigações": int(pend_obr),
            "Status": legal_status_site(taxa_obr, pend_obr),
            "_taxa_leg": float(taxa_leg),
            "_taxa_obr": float(taxa_obr),
            "_pend_total": int(pend_leg + pend_obr),
        })
    out = pd.DataFrame(rows)
    if not out.empty:
        out = out.sort_values(["_taxa_obr", "_pend_total"], ascending=[True, False])
    return out

def legal_styler_resumo_sites(df):
    if df is None or df.empty:
        return df
    def taxa_from_val(v):
        try:
            return float(str(v).replace("%", "").replace(",", "."))
        except Exception:
            return 0.0
    def style_row(row):
        cor_status = {
            "Em conformidade": "background-color:#dcfce7;color:#14532d;font-weight:800;",
            "Bom acompanhamento": "background-color:#e0f2fe;color:#075985;font-weight:800;",
            "Atenção": "background-color:#fef9c3;color:#713f12;font-weight:800;",
            "Prioritário": "background-color:#fee2e2;color:#7f1d1d;font-weight:800;",
        }.get(row.get("Status"), "")
        styles = []
        for col in row.index:
            if col == "Atend. legislação":
                taxa = taxa_from_val(row.get(col))
                styles.append(f"background-color:{'#dcfce7' if taxa >= LEGAL_META_ATENDIMENTO else '#fef9c3' if taxa >= 85 else '#fee2e2'};color:#111827;font-weight:800;")
            elif col == "Atend. obrigações":
                taxa = taxa_from_val(row.get(col))
                styles.append(f"background-color:{'#dcfce7' if taxa >= LEGAL_META_ATENDIMENTO else '#fef9c3' if taxa >= 85 else '#fee2e2'};color:#111827;font-weight:800;")
            elif col == "Status":
                styles.append(cor_status)
            elif col in ["Pend. legislação", "Pend. obrigações"] and row.get(col, 0):
                styles.append("color:#991b1b;font-weight:800;")
            else:
                styles.append("color:#111827;")
        return styles
    return df.style.apply(style_row, axis=1)

def legal_formata_tabela(df):
    if df is None or df.empty:
        return pd.DataFrame()
    cols = ["Site", "Divisão", "Origem base", "Legislação", "Status legislação", "Obrigação", "Status obrigação", "Assunto", "Âmbito/Origem", "Responsável obrigação", "Data preenchimento"]
    out = df[[c for c in cols if c in df.columns]].copy()
    for c in ["Data preenchimento"]:
        if c in out.columns:
            out[c] = out[c].apply(fmt_date)
    return out

